import { aedis_build, aedis_memory, aedis_loqui } from "../../../../modules/system/caput/tools.js";

const API = `http://127.0.0.1:${process.env["SQUIDLEY_API_PORT"] ?? "18791"}`;

async function get<T>(path: string, timeoutMs = 3000): Promise<T | null> {
  const url = `${API}${path}`;
  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(timeoutMs) });
    if (!res.ok) return null;
    try {
      return await res.json() as T;
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      console.warn(`[awareness] fetch failed: json parse failed for ${url}: ${reason}`);
      return null;
    }
  } catch (error) {
    if (error instanceof DOMException && error.name === "TimeoutError") {
      console.warn(`[awareness] fetch failed: timeout for ${url} after ${timeoutMs}ms`);
      return null;
    }
    const reason = error instanceof Error ? error.message : String(error);
    console.warn(`[awareness] fetch failed: fetch failed for ${url}: ${reason}`);
    return null;
  }
}

function clip(s: string, max = 80): string {
  return s.length <= max ? s : s.slice(0, max - 1) + "…";
}

function stamp(): string {
  return new Intl.DateTimeFormat("en-US", { dateStyle: "medium", timeStyle: "short", timeZone: process.env["TZ"] || "America/Chicago" }).format(new Date());
}

function ago(iso: string): string {
  const ms = Date.now() - new Date(iso).getTime();
  const m = Math.floor(ms / 60000);
  if (m < 1) return "just now";
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  return d === 1 ? "yesterday" : `${d}d ago`;
}

function stale(iso: string | null): boolean {
  if (!iso) return true;
  const ts = new Date(iso).getTime();
  if (Number.isNaN(ts)) return true;
  return Date.now() - ts > 3600_000; // >1h = stale
}

function compareNumbersDesc(a: number, b: number): number {
  return b - a;
}

function latestIso(values: Array<string | null | undefined>): string | null {
  let latest: string | null = null;
  let latestTs = Number.NEGATIVE_INFINITY;
  for (const value of values) {
    if (!value) continue;
    const ts = Date.parse(value);
    if (Number.isNaN(ts)) continue;
    if (ts > latestTs) {
      latestTs = ts;
      latest = value;
    }
  }
  return latest;
}

function unavailable(module: string): string {
  return `I can't reach ${module} right now — the service may need a restart. Check system health if this persists.`;
}

export const SYSTEM_AWARENESS_TOOLS = [

  // ── Agents ────────────────────────────────────────────────────────────────
  {
    id: "squidley.awareness.agents",
    name: "Agent Status",
    description: "What agents are doing, what failed, what's next, full schedule, and conflict detection",
    category: "system",
    trigger: ["agent", "legatus", "morning briefing", "news digest", "sibyl", "mercatus", "cursus agents", "job scout", "market monitor", "vigil", "custos", "recruiter", "resume tailor", "comms drafter", "lister", "negotiator", "what ran", "agent report", "briefing", "read me", "read the", "show me the report", "what did the", "schedule", "scheduled", "what's scheduled", "tonight", "tomorrow", "upcoming", "next run", "what runs", "conflicts"],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const [agents, stats] = await Promise.all([
        get<{ ok: boolean; agents: Array<{ id: string; name: string; active: boolean; lastRun: string | null; lastStatus: string; nextRun: string | null; schedule?: string; group?: string }> }>("/legatus/agents"),
        get<{ ok: boolean; stats: { activeAgents: number; totalRunsToday: number; successRateToday: number; agentSpendToday: number; nextScheduledRun: { agentName: string; nextRun: string } | null } }>("/legatus/stats"),
      ]);
      if (!agents?.ok) return { success: false, text: unavailable("Legatus"), durationMs: Date.now() - start };

      const list = agents.agents;
      const s = stats?.stats;
      const query = input?.query?.toLowerCase() ?? "";
      const lines: string[] = [`[${stamp()}, live data]`];

      // ── Determine query mode ──
      const wantsSchedule = /schedule|tonight|tomorrow|upcoming|next run|what runs|what's scheduled|what is scheduled/.test(query);
      const wantsConflicts = /conflict|overlap|collision|same time/.test(query);
      const wantsReport = /read|briefing|show me|tell me about|what did|full report/.test(query);

      // Parse time window from query (e.g., "next 12 hours", "tonight", "tomorrow")
      let windowHours = 24; // default: next 24 hours
      const hourMatch = query.match(/(\d+)\s*hours?/);
      if (hourMatch) windowHours = Math.min(Number(hourMatch[1]), 168);
      if (/tonight/.test(query)) windowHours = 12;
      if (/tomorrow/.test(query)) windowHours = 36;
      if (/this week/.test(query)) windowHours = 168;

      const now = Date.now();
      const windowEnd = now + windowHours * 3600_000;

      // ── Build schedule data ──
      const scheduled = list
        .filter(a => a.active && a.nextRun)
        .map(a => ({ ...a, nextRunMs: new Date(a.nextRun!).getTime() }))
        .sort((a, b) => a.nextRunMs - b.nextRunMs);

      const inWindow = scheduled.filter(a => a.nextRunMs >= now && a.nextRunMs <= windowEnd);

      // ── Conflict detection: agents within 15 min of each other ──
      const conflicts: Array<{ a: string; b: string; gap: number; time: string }> = [];
      for (let i = 0; i < inWindow.length; i++) {
        for (let j = i + 1; j < inWindow.length; j++) {
          const gap = Math.abs(inWindow[i]!.nextRunMs - inWindow[j]!.nextRunMs);
          if (gap < 15 * 60_000) {
            conflicts.push({
              a: inWindow[i]!.name,
              b: inWindow[j]!.name,
              gap: Math.round(gap / 60_000),
              time: new Date(inWindow[i]!.nextRunMs).toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", timeZone: process.env["TZ"] || "America/Chicago" }),
            });
          }
        }
      }

      // ── Schedule / conflict query ──
      if (wantsSchedule || wantsConflicts) {
        if (inWindow.length === 0) {
          lines.push(`No agents scheduled in the next ${windowHours} hours.`);
        } else {
          lines.push(`Schedule (next ${windowHours}h):`);
          for (const a of inWindow) {
            const time = new Date(a.nextRunMs).toLocaleString("en-US", {
              weekday: "short", hour: "2-digit", minute: "2-digit",
              timeZone: process.env["TZ"] || "America/Chicago",
            });
            lines.push(`  ${time} — ${a.name}${a.schedule ? ` (${a.schedule})` : ""}`);
          }
        }
        if (conflicts.length > 0) {
          lines.push("");
          lines.push(`⚠ ${conflicts.length} scheduling conflict${conflicts.length > 1 ? "s" : ""} detected:`);
          for (const c of conflicts) {
            lines.push(`  ${c.a} and ${c.b} — ${c.gap}min apart at ~${c.time}`);
          }
        } else if (wantsConflicts) {
          lines.push("No scheduling conflicts in the window.");
        }
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      // ── Default: status overview ──
      const failed = list.filter(a => a.lastStatus === "failed" && a.active);
      const neverRun = list.filter(a => a.active && !a.lastRun);
      const recent = list.filter(a => a.lastRun).sort((a, b) => (b.lastRun ?? "").localeCompare(a.lastRun ?? ""));

      if (failed.length > 0) {
        lines.push(`${failed.map(a => a.name).join(" and ")} failed on last run. Worth investigating — check history or re-trigger.`);
      }
      if (neverRun.length > 0 && neverRun.length <= 3) {
        lines.push(`${neverRun.map(a => a.name).join(", ")} ${neverRun.length === 1 ? "has" : "have"} never run — might need a manual trigger or the schedule hasn't hit yet.`);
      }
      if (failed.length === 0 && (s?.successRateToday ?? 100) === 100 && (s?.totalRunsToday ?? 0) > 0) {
        lines.push(`Clean day — ${s!.totalRunsToday} runs, all successful.`);
      } else if ((s?.successRateToday ?? 100) < 80) {
        lines.push(`Success rate is ${s?.successRateToday}% today across ${s?.totalRunsToday} runs — below normal.`);
      }

      const last3 = recent.slice(0, 4);
      if (last3.length > 0) {
        lines.push("Recent: " + last3.map(a => `${a.name} ${a.lastStatus === "success" ? "✓" : "✗"} ${ago(a.lastRun!)}`).join(" · "));
      }

      // Always show full upcoming schedule in default view
      if (inWindow.length > 0) {
        lines.push("");
        lines.push(`Upcoming (next ${windowHours}h):`);
        for (const a of inWindow.slice(0, 8)) {
          const time = new Date(a.nextRunMs).toLocaleString("en-US", {
            weekday: "short", hour: "2-digit", minute: "2-digit",
            timeZone: process.env["TZ"] || "America/Chicago",
          });
          lines.push(`  ${time} — ${a.name}`);
        }
        if (inWindow.length > 8) lines.push(`  ... and ${inWindow.length - 8} more`);
      }

      if (conflicts.length > 0) {
        lines.push("");
        lines.push(`⚠ ${conflicts.length} scheduling conflict${conflicts.length > 1 ? "s" : ""}:`);
        for (const c of conflicts) {
          lines.push(`  ${c.a} and ${c.b} — ${c.gap}min apart at ~${c.time}`);
        }
      }

      if ((s?.agentSpendToday ?? 0) > 0.05) {
        lines.push(`Agents have spent $${s!.agentSpendToday.toFixed(4)} today — Oculus has the breakdown.`);
      }

      // Report reading
      if (wantsReport && recent.length > 0) {
        const targetAgent = list.find(a => query.includes(a.name.toLowerCase()) || query.includes(a.id.toLowerCase())) ?? recent[0];
        if (targetAgent) {
          const history = await get<{ ok: boolean; history: Array<{ output: string; status: string; startedAt: string }> }>(`/legatus/agents/${targetAgent.id}/history`);
          const lastRun = history?.history?.[0];
          if (lastRun?.output) {
            lines.push("");
            lines.push(`--- ${targetAgent.name} report (${ago(lastRun.startedAt)}) ---`);
            lines.push(lastRun.output.slice(0, 2000));
            if (lastRun.output.length > 2000) lines.push("... (truncated)");
          }
        }
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Crucible ──────────────────────────────────────────────────────────────
  {
    id: "squidley.awareness.crucible",
    name: "Crucible Benchmarks",
    description: "Which models are good at what, and which aren't",
    category: "system",
    trigger: ["benchmark", "crucible", "personality test", "leaderboard", "model score", "how did", "personality result", "best model", "model performance"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const [lb, plb] = await Promise.all([
        get<{ ok: boolean; models: Array<{ model_name: string; overall_score: number; runs: number; is_local: boolean; last_run: string; best_scores: Record<string, number> }> }>("/crucible/leaderboard"),
        get<{ ok: boolean; models: Array<{ model_name: string; average_score: number; best_score: number; runs: number }> }>("/personality/leaderboard"),
      ]);
      if (!lb?.ok) return { success: false, text: unavailable("Crucible"), durationMs: Date.now() - start };

      const lines: string[] = [`[${stamp()}, live data]`];
      const cloud = [...lb.models.filter(m => !m.is_local)].sort((a, b) => compareNumbersDesc(a.overall_score, b.overall_score));
      const local = [...lb.models.filter(m => m.is_local)].sort((a, b) => compareNumbersDesc(a.overall_score, b.overall_score));
      const personalityModels = plb?.ok ? [...plb.models].sort((a, b) => compareNumbersDesc(a.average_score, b.average_score)) : [];

      if (cloud.length > 0) {
        const best = cloud[0]!;
        lines.push(`Best cloud model overall: ${best.model_name} at ${best.overall_score} across ${best.runs} runs.`);
        // Find what it's particularly good/bad at
        const scores = Object.entries(best.best_scores).sort(([,a],[,b]) => b - a);
        const strong = scores.filter(([,s]) => s >= 80).slice(0, 3);
        const weak = scores.filter(([,s]) => s < 40 && s >= 0);
        if (strong.length) lines.push(`Strong at: ${strong.map(([s,v]) => `${s} (${v})`).join(", ")}.`);
        if (weak.length) lines.push(`Weak at: ${weak.map(([s,v]) => `${s} (${v})`).join(", ")} — might want a specialist for these.`);
        if (cloud.length > 1) {
          lines.push(`Runner-up: ${cloud[1]!.model_name} (${cloud[1]!.overall_score}).`);
        }
      }

      if (local.length > 0) {
        lines.push(`Best local: ${local[0]!.model_name} (${local[0]!.overall_score}).`);
      }

      if (plb?.ok && personalityModels.length > 0) {
        const p = personalityModels[0]!;
        lines.push(`Personality leader: ${p.model_name} averaging ${p.average_score}.`);
      }

      const latest = latestIso(lb.models.map((model) => model.last_run));
      if (latest && stale(latest)) {
        lines.push(`Last benchmark was ${ago(latest)} — might be worth a fresh run.`);
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Magister ──────────────────────────────────────────────────────────────
  {
    id: "squidley.awareness.magister",
    name: "Magister Learning",
    description: "Learning campaigns, companion sessions, mastery progress",
    category: "system",
    trigger: ["magister", "learning", "vietnamese", "mandarin", "linh", "wei", "campaign", "lesson", "study", "progress", "mastery", "companion"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const [mods, sessions] = await Promise.all([
        get<{ ok: boolean; modules: Array<{ id: string; name: string; subject: string; installed: number; campaign_world: string }> }>("/magister/modules"),
        get<{ ok: boolean; sessions: Array<{ module_id: string; companion_id: string; status: string; teaching_mode: string; elapsed_seconds: number; updated_at: string }> }>("/magister/sessions"),
      ]);
      if (!mods?.ok) return { success: false, text: unavailable("Magister"), durationMs: Date.now() - start };

      const lines: string[] = [`[${stamp()}, live data]`];
      const installed = mods.modules.filter(m => m.installed);
      const active = (sessions?.sessions ?? []).filter(s => s.status === "active");
      const allSessions = sessions?.sessions ?? [];

      if (active.length > 0) {
        for (const s of active.slice(0, 3)) {
          const mod = mods.modules.find(m => m.id === s.module_id);
          const mins = Math.floor(s.elapsed_seconds / 60);
          const lastTouch = s.updated_at ? ago(s.updated_at) : "unknown";
          lines.push(`Active campaign in ${mod?.campaign_world ?? mod?.name ?? s.module_id} with ${s.companion_id} — ${mins} minutes invested, last session ${lastTouch}.`);
          if (stale(s.updated_at)) {
            lines.push(`  That session hasn't been touched in a while — ${s.companion_id} is waiting.`);
          }
        }
      } else if (installed.length > 0) {
        lines.push(`No active campaigns. ${installed.length} module${installed.length > 1 ? "s" : ""} installed (${installed.map(m => m.name).join(", ")}) — ready when you are.`);
      } else {
        lines.push(`${mods.modules.length} modules available but none installed yet. Vietnamese (Làng Sương) and Mandarin (Yún Chéng) are ready to go.`);
      }

      if (allSessions.length > 0) {
        const totalMins = allSessions.reduce((s, x) => s + (x.elapsed_seconds ?? 0), 0) / 60;
        if (totalMins > 10) lines.push(`Total time invested across all sessions: ${Math.floor(totalMins)} minutes.`);
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Spend ─────────────────────────────────────────────────────────────────
  {
    id: "squidley.awareness.spend",
    name: "Cost & Spend",
    description: "Where the money is going — model tokens, voice, music, video, and whether it's reasonable",
    category: "system",
    trigger: ["spend", "cost", "money", "budget", "how much", "receipt", "oculus", "tabularium", "token", "credits", "expensive", "elevenlabs", "voice cost", "music cost"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const [budget, credits] = await Promise.all([
        get<{ ok: boolean; totalSpent: number; byModule: Array<{ module: string; totalCost: number; callCount: number }>; mediaSpend?: Array<{ service: string; totalCost: number; callCount: number }> }>("/oculus/budget?days=1"),
        get<{ ok: boolean; charactersUsed: number; characterLimit: number; percentUsed: number; lowCredits: boolean; tier: string }>("/elevenlabs/credits"),
      ]);

      const lines: string[] = [`[${stamp()}, live data]`];

      if (!budget?.ok) {
        lines.push("Can't reach the budget data right now.");
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      const total = budget.totalSpent ?? 0;
      const topModules = (budget.byModule ?? []).filter(m => m.totalCost > 0).sort((a, b) => b.totalCost - a.totalCost);

      if (total < 0.01) {
        lines.push("Barely anything spent today — under a penny. Running lean.");
      } else if (total < 0.50) {
        lines.push(`$${total.toFixed(4)} today. Normal range.`);
      } else if (total < 2.00) {
        lines.push(`$${total.toFixed(4)} today — moderate. Probably a benchmark run or heavy agent activity.`);
      } else {
        lines.push(`$${total.toFixed(2)} today — that's elevated. Worth checking what's driving it.`);
      }

      if (topModules.length > 0) {
        const top = topModules[0]!;
        const topName = top.module.split(".").pop() ?? top.module;
        if (topModules.length === 1 || top.totalCost > total * 0.7) {
          lines.push(`Almost all of it is ${topName} ($${top.totalCost.toFixed(4)}, ${top.callCount} calls).`);
        } else {
          lines.push(`Split across ${topModules.slice(0, 3).map(m => `${m.module.split(".").pop()} $${m.totalCost.toFixed(4)}`).join(", ")}.`);
        }
      }

      // Media spend (voice, music, video)
      const media = budget.mediaSpend ?? [];
      if (media.length > 0) {
        lines.push("");
        lines.push("Media spend:");
        for (const m of media) {
          lines.push(`  ${m.service}: $${m.totalCost.toFixed(4)} (${m.callCount} call${m.callCount !== 1 ? "s" : ""})`);
        }
      }

      // ElevenLabs credits
      if (credits?.ok) {
        lines.push("");
        const pct = credits.percentUsed;
        lines.push(`ElevenLabs (${credits.tier}): ${credits.charactersUsed.toLocaleString()} / ${credits.characterLimit.toLocaleString()} characters (${pct}% used).`);
        if (credits.lowCredits) {
          lines.push(`⚠ ElevenLabs credits are low (${100 - pct}% remaining). Consider reducing voice output or upgrading tier.`);
        }
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Archelon (Health) ─────────────────────────────────────────────────────
  {
    id: "squidley.awareness.archelon",
    name: "System Health",
    description: "What's healthy, what's degraded, what needs attention",
    category: "system",
    trigger: ["archelon", "finding", "critical", "alert", "warning", "anomaly", "health", "system health", "what's wrong", "issues", "degraded"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const [findings, health] = await Promise.all([
        get<{ findings: Array<{ title: string; severity: string; category: string; timestamp: string }> }>("/archelon/findings?limit=10"),
        get<{ modules: Record<string, { status: string; message?: string; expectedDegraded?: boolean }> }>("/health"),
      ]);

      const lines: string[] = [`[${stamp()}, live data]`];

      if (health?.modules) {
        const mods = Object.entries(health.modules);
        const ON_DEMAND = new Set(["squidley.integration.comfyui", "squidley.integration.provider-llamacpp", "squidley.integration.provider-zai", "squidley.integration.opencode"]);
        const degraded = mods.filter(([name, v]) => (v.status === "degraded" || v.status === "failed") && !ON_DEMAND.has(name));

        if (degraded.length === 0) {
          lines.push(`All ${mods.length} modules healthy. Nothing to worry about.`);
        } else if (degraded.length <= 2) {
          for (const [name, v] of degraded) {
            const short = name.split(".").pop();
            const isExpected = Boolean(v.expectedDegraded) || name.includes("llamacpp") || name.includes("comfyui");
            if (isExpected) {
              lines.push(`${short} is ${v.status} — expected (it's an optional service that starts on demand).`);
            } else {
              lines.push(`${short} is ${v.status}${v.message ? `: ${clip(v.message, 60)}` : ""}. May need a restart or config fix.`);
            }
          }
        } else {
          lines.push(`${degraded.length} modules degraded — that's unusual. Might be a connectivity issue or a recent restart that didn't complete cleanly.`);
          for (const [name, v] of degraded.slice(0, 3)) {
            lines.push(`  ${name.split(".").pop()}: ${v.status}`);
          }
        }
      } else {
        lines.push("Can't reach the health endpoint — that's concerning in itself.");
      }

      const critical = (findings?.findings ?? []).filter(f => f.severity === "critical" || f.severity === "warn");
      if (critical.length > 0) {
        const recent = critical.filter(f => !stale(f.timestamp));
        if (recent.length > 0) {
          lines.push(`${recent.length} recent finding${recent.length > 1 ? "s" : ""}: ${recent.slice(0, 2).map(f => `[${f.severity}] ${clip(f.title, 60)}`).join("; ")}.`);
        }
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Syscheck (Unified Narrative) ──────────────────────────────────────────
  {
