          body: JSON.stringify({ mode: isFull ? "full" : "brief" }),
          signal: AbortSignal.timeout(15_000),
        });
        if (!res.ok) return { success: false, text: "Syscheck endpoint returned an error — check server logs.", durationMs: Date.now() - start };
        const data = await res.json() as { ok: boolean; briefing: string; mode: string };
        if (!data.ok) return { success: false, text: "Syscheck returned not-ok.", durationMs: Date.now() - start };
        return { success: true, text: `[${stamp()}, ${data.mode} syscheck]\n${data.briefing}`, durationMs: Date.now() - start };
