  {
    id: "squidley.awareness.animus",
    name: "Idea Vault",
    description: "What ideas Jeff has been thinking about — their age, potential, and what needs attention",
    category: "system",
    trigger: [
      "animus", "idea", "ideas", "vault", "what ideas", "my ideas",
