    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";
      const wantsErrors = /error|fail|broke|wrong/.test(query);
      const since = new Date(Date.now() - 30 * 60 * 1000).toISOString();
      const data = await get<{ ok: boolean; events: Array<{ timestamp: string; module: string; event: string; severity: string; detail?: string }> }>(`/events/stream?since=${encodeURIComponent(since)}&limit=50`);
      if (!data?.ok) return { success: false, text: unavailable("Event Bus"), durationMs: Date.now() - start };

      const events = data.events ?? [];
      const lines: string[] = [`[${stamp()}, live data — last 30 minutes]`];

      if (events.length === 0) {
        lines.push("No events in the last 30 minutes. System is quiet.");
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      const errors = events.filter(e => e.severity === "error");
      const warns = events.filter(e => e.severity === "warn");
      lines.push(`${events.length} events total: ${errors.length} errors, ${warns.length} warnings, ${events.length - errors.length - warns.length} info.`);

      if (errors.length > 0) {
        lines.push(""); lines.push("Errors:");
        for (const e of errors.slice(0, 5)) lines.push(`  ${ago(e.timestamp)} — [${e.module}] ${e.event}: ${clip(e.detail ?? "", 100)}`);
      }
      if (!wantsErrors && events.length > 0) {
        lines.push(""); lines.push("Recent:");
        for (const e of events.slice(-8)) lines.push(`  ${ago(e.timestamp)} — [${e.module}] ${e.event}${e.detail ? ": " + clip(e.detail, 80) : ""}`);
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

