  /** Global kill switch */
  enabled: boolean;

  /**
   * Escalation ladder — ordered low → high capability.
   * Each entry matches model name patterns (case-insensitive substring).
   * A model can only escalate to entries ABOVE it in the ladder.
   */
  ladder: Array<{
    /** Human label shown in the suggestion */
    label: string;
    /** Patterns to match against model name/id (any match = this tier) */
    patterns: string[];
    /** The model string to pass to the provider when escalating */
    modelId: string;
    /** Provider hint */
    provider: string;
  }>;

  /** Uncertainty signal phrases in model responses */
  uncertaintyPhrases: string[];

  /** Keywords in user messages that indicate complex requests */
  complexityKeywords: string[];

  /** Token estimate threshold — user messages above this are "complex" */
  complexTokenThreshold: number;

  /** Minimum response tokens expected for a complex request */
  shortResponseThreshold: number;

  /** How many consecutive uncertain/short responses before suggesting */
  consecutiveThreshold: number;
}

