    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const [agents, stats] = await Promise.all([
        get<{ ok: boolean; agents: Array<{ id: string; name: string; active: boolean; lastRun: string | null; lastStatus: string; nextRun: string | null; schedule?: string; group?: string }> }>("/legatus/agents"),
        get<{ ok: boolean; stats: { activeAgents: number; totalRunsToday: number; successRateToday: number; agentSpendToday: number; nextScheduledRun: { agentName: string; nextRun: string } | null } }>("/legatus/stats"),
      ]);
      if (!agents?.ok) return { success: false, text: unavailable("Legatus"), durationMs: Date.now() - start };

      const list = agents.agents;
      const s = stats?.stats;
      const query = input?.query?.toLowerCase() ?? "";
      const lines: string[] = [`[${stamp()}, live data]`];

      // ── Determine query mode ──
      const wantsSchedule = /schedule|tonight|tomorrow|upcoming|next run|what runs|what's scheduled|what is scheduled/.test(query);
      const wantsConflicts = /conflict|overlap|collision|same time/.test(query);
      const wantsReport = /read|briefing|show me|tell me about|what did|full report/.test(query);

      // Parse time window from query (e.g., "next 12 hours", "tonight", "tomorrow")
      let windowHours = 24; // default: next 24 hours
      const hourMatch = query.match(/(\d+)\s*hours?/);
      if (hourMatch) windowHours = Math.min(Number(hourMatch[1]), 168);
      if (/tonight/.test(query)) windowHours = 12;
      if (/tomorrow/.test(query)) windowHours = 36;
      if (/this week/.test(query)) windowHours = 168;

      const now = Date.now();
      const windowEnd = now + windowHours * 3600_000;

      // ── Build schedule data ──
      const scheduled = list
        .filter(a => a.active && a.nextRun)
        .map(a => ({ ...a, nextRunMs: new Date(a.nextRun!).getTime() }))
        .sort((a, b) => a.nextRunMs - b.nextRunMs);

      const inWindow = scheduled.filter(a => a.nextRunMs >= now && a.nextRunMs <= windowEnd);

      // ── Conflict detection: agents within 15 min of each other ──
      const conflicts: Array<{ a: string; b: string; gap: number; time: string }> = [];
      for (let i = 0; i < inWindow.length; i++) {
        for (let j = i + 1; j < inWindow.length; j++) {
          const gap = Math.abs(inWindow[i]!.nextRunMs - inWindow[j]!.nextRunMs);
          if (gap < 15 * 60_000) {
            conflicts.push({
              a: inWindow[i]!.name,
              b: inWindow[j]!.name,
              gap: Math.round(gap / 60_000),
              time: new Date(inWindow[i]!.nextRunMs).toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", timeZone: process.env["TZ"] || "America/Chicago" }),
            });
          }
        }
      }

      // ── Schedule / conflict query ──
      if (wantsSchedule || wantsConflicts) {
        if (inWindow.length === 0) {
          lines.push(`No agents scheduled in the next ${windowHours} hours.`);
        } else {
          lines.push(`Schedule (next ${windowHours}h):`);
          for (const a of inWindow) {
            const time = new Date(a.nextRunMs).toLocaleString("en-US", {
              weekday: "short", hour: "2-digit", minute: "2-digit",
              timeZone: process.env["TZ"] || "America/Chicago",
            });
            lines.push(`  ${time} — ${a.name}${a.schedule ? ` (${a.schedule})` : ""}`);
          }
        }
        if (conflicts.length > 0) {
          lines.push("");
          lines.push(`⚠ ${conflicts.length} scheduling conflict${conflicts.length > 1 ? "s" : ""} detected:`);
          for (const c of conflicts) {
            lines.push(`  ${c.a} and ${c.b} — ${c.gap}min apart at ~${c.time}`);
          }
        } else if (wantsConflicts) {
          lines.push("No scheduling conflicts in the window.");
        }
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      // ── Default: status overview ──
      const failed = list.filter(a => a.lastStatus === "failed" && a.active);
      const neverRun = list.filter(a => a.active && !a.lastRun);
      const recent = list.filter(a => a.lastRun).sort((a, b) => (b.lastRun ?? "").localeCompare(a.lastRun ?? ""));

      if (failed.length > 0) {
        lines.push(`${failed.map(a => a.name).join(" and ")} failed on last run. Worth investigating — check history or re-trigger.`);
      }
      if (neverRun.length > 0 && neverRun.length <= 3) {
        lines.push(`${neverRun.map(a => a.name).join(", ")} ${neverRun.length === 1 ? "has" : "have"} never run — might need a manual trigger or the schedule hasn't hit yet.`);
      }
      if (failed.length === 0 && (s?.successRateToday ?? 100) === 100 && (s?.totalRunsToday ?? 0) > 0) {
        lines.push(`Clean day — ${s!.totalRunsToday} runs, all successful.`);
      } else if ((s?.successRateToday ?? 100) < 80) {
        lines.push(`Success rate is ${s?.successRateToday}% today across ${s?.totalRunsToday} runs — below normal.`);
      }

      const last3 = recent.slice(0, 4);
      if (last3.length > 0) {
        lines.push("Recent: " + last3.map(a => `${a.name} ${a.lastStatus === "success" ? "✓" : "✗"} ${ago(a.lastRun!)}`).join(" · "));
      }

      // Always show full upcoming schedule in default view
      if (inWindow.length > 0) {
        lines.push("");
        lines.push(`Upcoming (next ${windowHours}h):`);
        for (const a of inWindow.slice(0, 8)) {
          const time = new Date(a.nextRunMs).toLocaleString("en-US", {
            weekday: "short", hour: "2-digit", minute: "2-digit",
            timeZone: process.env["TZ"] || "America/Chicago",
          });
          lines.push(`  ${time} — ${a.name}`);
        }
        if (inWindow.length > 8) lines.push(`  ... and ${inWindow.length - 8} more`);
      }

      if (conflicts.length > 0) {
        lines.push("");
        lines.push(`⚠ ${conflicts.length} scheduling conflict${conflicts.length > 1 ? "s" : ""}:`);
        for (const c of conflicts) {
          lines.push(`  ${c.a} and ${c.b} — ${c.gap}min apart at ~${c.time}`);
        }
      }

      if ((s?.agentSpendToday ?? 0) > 0.05) {
        lines.push(`Agents have spent $${s!.agentSpendToday.toFixed(4)} today — Oculus has the breakdown.`);
      }

      // Report reading
      if (wantsReport && recent.length > 0) {
        const targetAgent = list.find(a => query.includes(a.name.toLowerCase()) || query.includes(a.id.toLowerCase())) ?? recent[0];
        if (targetAgent) {
