  // ── Web Search — the anti-hallucination tool ─────────────────────────────
  {
    id: "squidley.tools.web_search",
    name: "Web Search",
    description: "Search the internet for current information. If the answer requires external data, use this — never guess.",
    category: "search",
    trigger: [
      "find", "look up", "search for", "what is the price", "where can I", "locate",
      "nearest", "cheapest", "best", "reviews for", "how much does", "is there a",
      "check if", "what are the", "compare", "search", "google", "look for",
      "what is", "who is", "when did", "latest", "current", "news", "how to",
      "where is", "tell me about", "price of", "cost of", "buy", "shop",
      "store near", "open now", "hours for", "phone number", "address of",
    ],
    requiresApproval: false,
    async execute(input: { query: string }) {
      const start = Date.now();
      const SEARXNG = process.env["SEARXNG_URL"] ?? "http://localhost:8888";
      const TAVILY_KEY = process.env["TAVILY_API_KEY"] ?? "";
      const query = input.query.trim();
      if (!query) return { success: false, text: "No search query provided.", durationMs: 0 };

      // Detect query type for format-aware output
      const isPrice = /price|cost|how much|cheap|buy|shop|\$/.test(query.toLowerCase());
      const isLocation = /near|nearest|where|address|hours|phone|locate|directions/.test(query.toLowerCase());
      const isReview = /review|best|recommend|vs|compare|worth|good|bad/.test(query.toLowerCase());

      interface SearchResult { title: string; url: string; content: string; engine?: string; publishedDate?: string }
      let results: SearchResult[] = [];

      // Try SearXNG first
      try {
        const params = new URLSearchParams({ q: query, format: "json", language: "en" });
        const res = await fetch(`${SEARXNG}/search?${params}`, {
          headers: { "User-Agent": "Squidley/2.0 (local AI assistant)" },
          signal: AbortSignal.timeout(10_000),
        });
        if (res.ok) {
          const data = await res.json() as { results?: SearchResult[] };
          results = (data.results ?? []).filter(r => r.title && r.url && r.content).slice(0, 8);
        }
      } catch { /* SearXNG down */ }

      // Fallback to Tavily if SearXNG returns sparse results
      if (results.length < 3 && TAVILY_KEY) {
        try {
          const res = await fetch("https://api.tavily.com/search", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ api_key: TAVILY_KEY, query, search_depth: "basic", max_results: 5 }),
            signal: AbortSignal.timeout(15_000),
          });
          if (res.ok) {
            const data = await res.json() as { results?: Array<{ title: string; url: string; content: string }> };
            const tavily = (data.results ?? []).map(r => ({ ...r, engine: "tavily" }));
            // Merge — dedup by URL
            const seen = new Set(results.map(r => r.url));
            for (const r of tavily) { if (!seen.has(r.url)) { results.push(r); seen.add(r.url); } }
          }
        } catch { /* Tavily down */ }
      }

      if (results.length === 0) {
        // Second attempt with refined query
        try {
          const refined = query.replace(/\b(find|search for|look up|what is|tell me about)\b/gi, "").trim();
          if (refined !== query && refined.length > 3) {
            const params = new URLSearchParams({ q: refined, format: "json", language: "en" });
            const res = await fetch(`${SEARXNG}/search?${params}`, {
              headers: { "User-Agent": "Squidley/2.0 (local AI assistant)" },
              signal: AbortSignal.timeout(10_000),
            });
            if (res.ok) {
              const data = await res.json() as { results?: SearchResult[] };
              results = (data.results ?? []).filter(r => r.title && r.url && r.content).slice(0, 5);
            }
          }
        } catch { /* still nothing */ }
      }

      if (results.length === 0) {
        return { success: false, text: `No search results found for "${query}". Search engines may be temporarily unavailable.`, durationMs: Date.now() - start };
      }

      // Synthesize based on query type
      const top = results.slice(0, 5);
      const lines: string[] = [`[Web search results for: "${clip(query, 60)}"]`];

      if (isPrice) {
        for (const r of top) {
          const priceMatch = r.content.match(/\$[\d,.]+/);
          lines.push(`${r.title}${priceMatch ? ` — ${priceMatch[0]}` : ""}\n  ${clip(r.content, 120)}\n  ${r.url}`);
        }
      } else if (isLocation) {
        for (const r of top) {
          lines.push(`${r.title}\n  ${clip(r.content, 150)}\n  ${r.url}`);
        }
      } else if (isReview) {
        // Synthesize pros/cons from multiple sources
        lines.push("Summary from multiple sources:");
        for (const r of top.slice(0, 4)) {
          lines.push(`• ${r.title}: ${clip(r.content, 100)}\n  Source: ${r.url}`);
        }
      } else {
        // General search — synthesize
        for (const r of top.slice(0, 4)) {
          lines.push(`${r.title}\n  ${clip(r.content, 120)}\n  ${r.url}`);
        }
      }

      lines.push(`\n${results.length} results found. Data is from live web search, not from memory.`);

      return { success: true, text: lines.join("\n\n"), durationMs: Date.now() - start };
    },
  },
  // ── Unified Search ──────────────────────────────────────────────────────
  {
