  // ── Sibyl — Office Manager / System Self-Awareness ──────────────────────
  {
    id: "squidley.awareness.sibyl",
    name: "Sibyl (Office Manager)",
    description: "Sibyl's gap ledger, system audit status, and self-awareness layer. Knows what works, what's broken, and what was promised but never proven.",
    category: "system",
    trigger: [
      "sibyl", "ask sibyl", "what does sibyl think", "sibyl's report",
