    async execute() {
      const start = Date.now();

      // Fetch gap ledger
      const gapData = await get<{
        ok: boolean;
        gaps: Array<{ module: string; promise: string; status: string; severity: string; notes: string | null; last_checked: string | null }>;
        counts: { total: number; proven: number; partial: number; gap: number; unknown: number };
      }>("/sibyl/gap-ledger", 5000);

      // Fetch recent audit reports
      const reportData = await get<{
        ok: boolean;
        reports: Array<{ title: string; content: string; createdAt?: number }>;
      }>("/sibyl/audit/reports", 3000);

      if (!gapData?.ok) return { success: false, text: "Sibyl's gap ledger is not available. Run an audit first from Imperium → Sibyl tab.", durationMs: Date.now() - start };

      const lines: string[] = [`[${stamp()}, live data from Sibyl — system office manager]`];

      lines.push("Sibyl is Squidley's self-awareness layer. She tracks what every module promises to do, and whether that promise has been proven.");
      lines.push("");

      // Gap summary
      const c = gapData.counts;
      lines.push(`Gap Ledger: ${c.total} modules tracked — ${c.proven} proven, ${c.partial} partial, ${c.gap} gaps, ${c.unknown} unknown.`);

      // Surface problems
      const problems = gapData.gaps.filter(g => g.status === "gap" || g.status === "partial");
      if (problems.length > 0) {
        lines.push("");
        lines.push("Needs attention:");
        for (const g of problems.slice(0, 8)) {
          const mod = g.module.split(".").pop() ?? g.module;
          lines.push(`- [${g.status}/${g.severity}] ${mod}: ${g.promise.slice(0, 80)}${g.notes ? ` — ${g.notes.slice(0, 60)}` : ""}`);
