      } else {
        lines.push("All systems nominal — no gaps or partial failures detected.");
      }

      // Latest audit
      if (reportData?.reports?.length) {
        const latest = reportData.reports[0]!;
        const when = latest.createdAt ? ago(new Date(latest.createdAt).toISOString()) : "unknown";
        lines.push("");
        lines.push(`Last audit: ${when} — ${latest.title}`);
      }

      lines.push("");
      lines.push("To talk to Sibyl directly, open Imperium → Sibyl tab. To run a fresh audit, ask Sibyl to 'run an audit' or use the Run Audit button.");

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
