  // ── Fabrica (Build Pipeline) ────────────────────────────────────────────
  {
    id: "squidley.awareness.fabrica",
    name: "Fabrica — Build Pipeline Status",
    description: "Current builds, last result, active jobs, sandbox output",
    category: "system",
    trigger: ["fabrica", "build", "build status", "build pipeline", "code gen", "generation pipeline", "what's building", "last build", "active build", "sandbox"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const sessions = await get<{ ok: boolean; sessions: Array<{
        id: string; name: string; mode: string; status: string;
        currentStage?: string; cards: Array<{ id: string; status: string; label: string; costUsd: number }>;
        sandboxPath?: string; createdAt: string; updatedAt: string; error?: string;
      }> }>("/fabrica/runtime/sessions");

      if (!sessions?.ok) return { success: false, text: unavailable("Fabrica"), durationMs: Date.now() - start };

      const lines: string[] = [`[${stamp()}, live data]`];
      const all = sessions.sessions ?? [];

      if (all.length === 0) {
        lines.push("No Fabrica builds on record.");
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      const running = all.filter(s => s.status === "running");
      const paused = all.filter(s => s.status === "paused");
      const complete = all.filter(s => s.status === "complete");
      const errored = all.filter(s => s.status === "error");

      if (running.length > 0) {
        lines.push(`${running.length} build${running.length > 1 ? "s" : ""} running:`);
        for (const s of running) {
          const stagesComplete = s.cards.filter(c => c.status === "complete").length;
          lines.push(`  "${s.name}" (${s.mode}) — stage ${s.currentStage ?? "?"}, ${stagesComplete}/${s.cards.length} complete`);
        }
      }

      if (paused.length > 0) {
        lines.push(`${paused.length} paused — may need approval or intervention.`);
      }

      if (errored.length > 0) {
        lines.push(`${errored.length} failed:`);
        for (const s of errored.slice(0, 3)) {
          lines.push(`  "${s.name}" — ${clip(s.error ?? "unknown error", 80)}`);
        }
      }

      // Most recent completed build
      const sorted = complete.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
      if (sorted.length > 0) {
        const last = sorted[0]!;
        const totalCost = last.cards.reduce((sum, c) => sum + (c.costUsd ?? 0), 0);
        lines.push("");
        lines.push(`Last completed: "${last.name}" (${last.mode}) — ${ago(last.updatedAt)}, $${totalCost.toFixed(4)}`);
        if (last.sandboxPath) {
          lines.push(`  Sandbox: ${last.sandboxPath}`);
        }
      }

      lines.push(`\nTotal: ${all.length} builds (${complete.length} complete, ${running.length} running, ${paused.length} paused, ${errored.length} errored)`);

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

