  // ── Imperium (Ticket System) ────────────────────────────────────────────
  {
    id: "squidley.awareness.imperium",
    name: "Imperium — Tickets & Self-Repair",
    description: "Open tickets, recent activity, severity breakdown, self-repair status",
    category: "system",
    trigger: ["imperium", "ticket", "tickets", "open tickets", "bug", "bugs", "issue", "issues", "self-repair", "what's broken", "what needs fixing", "regression"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const [tickets, stats] = await Promise.all([
        get<{ ok: boolean; tickets: Array<{ id: string; title: string; severity: string; status: string; source: string; module: string | null; hit_count: number; last_seen: string }>; counts: { total: number; open: number; active: number; fixed: number; deferred: number } }>("/imperium/tickets?status=active&limit=20"),
        get<{ ok: boolean; bySeverity: Array<{ severity: string; count: number }>; bySource: Array<{ source: string; count: number }>; recentEvents: Array<{ type: string; ticket_title: string; created_at: string }> }>("/imperium/stats"),
      ]);

      if (!tickets?.ok) return { success: false, text: unavailable("Imperium"), durationMs: Date.now() - start };

      const lines: string[] = [`[${stamp()}, live data]`];
      const counts = tickets.counts;
      const list = tickets.tickets ?? [];

      if (counts.active === 0) {
        lines.push("No active tickets. Quiet board.");
      } else {
        lines.push(`${counts.active} active ticket${counts.active !== 1 ? "s" : ""}${counts.fixed > 0 ? ` (${counts.fixed} fixed, ${counts.deferred} deferred)` : ""}`);

        // Severity breakdown
        const sevCounts = stats?.bySeverity ?? [];
        const critical = sevCounts.find(s => s.severity === "critical")?.count ?? 0;
        const high = sevCounts.find(s => s.severity === "high")?.count ?? 0;
        if (critical > 0) {
          lines.push(`  ⚠ ${critical} CRITICAL — needs immediate attention`);
        }
        if (high > 0) {
          lines.push(`  ${high} high severity`);
        }

        // Top tickets
        const topTickets = list.slice(0, 5);
        if (topTickets.length > 0) {
          lines.push("");
          for (const t of topTickets) {
            const repeat = t.hit_count > 1 ? ` (×${t.hit_count})` : "";
            lines.push(`  [${t.severity}] ${t.title}${repeat} — ${t.source}, ${ago(t.last_seen)}`);
          }
        }
      }

      // Recent activity
      const events = stats?.recentEvents ?? [];
      if (events.length > 0) {
        const recentOnes = events.filter(e => !stale(e.created_at)).slice(0, 3);
        if (recentOnes.length > 0) {
          lines.push("");
          lines.push("Recent activity:");
          for (const e of recentOnes) {
            lines.push(`  ${e.type}: ${clip(e.ticket_title, 50)} — ${ago(e.created_at)}`);
          }
        }
      }

      // Source breakdown if interesting
      const sources = stats?.bySource ?? [];
      const topSources = sources.filter(s => s.count > 1);
      if (topSources.length > 0) {
        lines.push("");
        lines.push("By source: " + topSources.map(s => `${s.source} (${s.count})`).join(", "));
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Mesh (Multi-Node Cluster) ───────────────────────────────────────────
  {
    id: "squidley.awareness.mesh",
    name: "Mesh — Cluster Nodes",
    description: "Remote Squidley nodes: who's online, capabilities, last check-in, live health",
    category: "system",
    trigger: ["mesh", "pop tart", "poptart", "cluster", "nodes", "remote", "worker", "is pop tart online", "mesh status", "distributed", "node status"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const registry = await get<{
        nodes: Array<{
          node: string; url: string; status: string;
          gpu: string | null; vram_gb: number | null;
          capabilities: string[]; registered_at: string; last_seen: string;
        }>;
        online_count: number; total_count: number;
      }>("/mesh/nodes");

      const lines: string[] = [`[${stamp()}, live data]`];

      if (!registry || registry.total_count === 0) {
        lines.push("No mesh nodes registered. Mushin is running solo.");
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      lines.push(`Mesh: ${registry.online_count}/${registry.total_count} node${registry.total_count !== 1 ? "s" : ""} online`);

      for (const node of registry.nodes) {
        lines.push("");
        const statusIcon = node.status === "online" ? "●" : "○";
        lines.push(`${statusIcon} ${node.node} — ${node.status}`);
        lines.push(`  URL: ${node.url}`);
        if (node.gpu) lines.push(`  GPU: ${node.gpu}${node.vram_gb ? ` (${node.vram_gb}GB VRAM)` : ""}`);
        if (node.capabilities.length > 0) lines.push(`  Capabilities: ${node.capabilities.join(", ")}`);
        lines.push(`  Registered: ${ago(node.registered_at)} · Last seen: ${ago(node.last_seen)}`);

        // Live health ping for online nodes
        if (node.status === "online") {
          try {
            const healthRes = await fetch(`${node.url}/health`, { signal: AbortSignal.timeout(3000) });
            if (healthRes.ok) {
              const health = await healthRes.json() as { status?: string; modules?: Record<string, unknown> };
              const modCount = health.modules ? Object.keys(health.modules).length : 0;
              lines.push(`  Health: ${health.status ?? "ok"}${modCount > 0 ? ` (${modCount} modules)` : ""} — reachable`);
            } else {
              lines.push(`  Health: responded ${healthRes.status} — may have issues`);
            }
          } catch {
            lines.push(`  Health: UNREACHABLE — node may be down despite "online" status`);
          }
        }
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Shared Context (Mesh Working Memory) ────────────────────────────────
  {
    id: "squidley.awareness.context",
    name: "Shared Context",
    description: "Working context shared across all mesh nodes — active projects, tasks, decisions, conversation summaries",
    category: "system",
    trigger: ["shared context", "mesh context", "what does pop tart know", "what is pop tart working on", "shared memory", "context sync", "broadcast", "tell pop tart", "share with pop tart"],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";

      // If user wants to share/broadcast something
      const wantsBroadcast = /tell pop tart|share with|broadcast|let .* know/.test(query);
      if (wantsBroadcast) {
        const content = query.replace(/tell pop tart|share with pop tart|broadcast|let .* know/gi, "").trim();
        if (content.length > 5) {
          try {
            await fetch(`${API}/mesh/context/broadcast`, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ type: "conversation_summary", content, source: "mushin" }),
              signal: AbortSignal.timeout(10_000),
            });
            return { success: true, text: `Shared with mesh: "${content}"`, durationMs: Date.now() - start };
          } catch {
            return { success: false, text: "Failed to broadcast to mesh.", durationMs: Date.now() - start };
          }
        }
      }

      // Otherwise, show current shared context
      const data = await get<{ ok: boolean; entries: Array<{ key: string; value: unknown; source: string; updated_at: string; tags: string[] }>; total: number }>("/mesh/context");
      if (!data?.ok || data.total === 0) {
        return { success: true, text: `[${stamp()}] No shared context entries. The mesh nodes aren't sharing working state yet.\nUse "tell Pop Tart [message]" or "share with Pop Tart [info]" to broadcast context.`, durationMs: Date.now() - start };
      }

      const lines = [`[${stamp()}, ${data.total} shared context entries]`];
      for (const e of data.entries.slice(0, 10)) {
        const val = typeof e.value === "object" && e.value !== null ? (e.value as Record<string, unknown>).content ?? JSON.stringify(e.value).slice(0, 100) : String(e.value).slice(0, 100);
        lines.push(`  [${e.source}] ${e.tags.join(", ")} — ${val} (${ago(e.updated_at)})`);
      }
      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

