      const path = wantsFull ? "/awareness/report" : "/awareness/briefing";
      try {
        const res = await fetch(`${API}${path}`, { signal: AbortSignal.timeout(8_000) });
        if (!res.ok) return { success: false, text: `Awareness endpoint returned ${res.status}.`, durationMs: Date.now() - start };
        const data = await res.json() as { ok: boolean; briefing?: { severity: string; summary: string; topWarnings: string[]; topActions: string[] }; report?: { severity: string; summary: string; warnings: Array<{ title: string; detail?: string }>; recommendedActions: Array<{ title: string; rationale: string }>; recentFailures: Array<{ title: string }>; openLoops: Array<{ title: string }>; sources: { ok: string[]; unavailable: Array<{ source: string; reason: string }> } } };
        if (!data.ok) return { success: false, text: "Awareness report returned not-ok.", durationMs: Date.now() - start };
        const lines: string[] = [`[${stamp()}, Squidley awareness]`];
        if (data.briefing) {
          const b = data.briefing;
          lines.push(`Severity: ${b.severity.toUpperCase()} — ${b.summary}`);
          if (b.topWarnings.length) {
            lines.push("");
            lines.push("Top warnings:");
            for (const w of b.topWarnings) lines.push(`  - ${w}`);
          }
          if (b.topActions.length) {
            lines.push("");
            lines.push("Top recommended actions:");
            for (const a of b.topActions) lines.push(`  - ${a}`);
          }
        } else if (data.report) {
          const r = data.report;
          lines.push(`Severity: ${r.severity.toUpperCase()} — ${r.summary}`);
          if (r.warnings.length) {
            lines.push("");
            lines.push("Warnings:");
            for (const w of r.warnings.slice(0, 5)) lines.push(`  - ${w.title}${w.detail ? ` — ${clip(w.detail, 100)}` : ""}`);
          }
          if (r.recentFailures.length) {
            lines.push("");
            lines.push("Recent failures:");
            for (const f of r.recentFailures.slice(0, 3)) lines.push(`  - ${f.title}`);
          }
          if (r.openLoops.length) {
            lines.push("");
            lines.push("Open loops:");
            for (const o of r.openLoops.slice(0, 3)) lines.push(`  - ${o.title}`);
          }
          if (r.recommendedActions.length) {
            lines.push("");
            lines.push("Recommended actions:");
            for (const a of r.recommendedActions.slice(0, 4)) lines.push(`  - ${a.title} — ${clip(a.rationale, 120)}`);
          }
          lines.push("");
          lines.push(`Sources: ${r.sources.ok.join(", ") || "none"}${r.sources.unavailable.length ? ` (unavailable: ${r.sources.unavailable.map(u => u.source).join(", ")})` : ""}`);
        }
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      } catch (err) {
        return { success: false, text: `Awareness lookup failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
      }
    },
  },

