  {
    id: "squidley.awareness.repair",
    name: "Repair Plans",
    description: "Phase 4 repair orchestration — lists proposed and in-flight repair plans, their approval state, step status, and verification outcome.",
    category: "system",
    trigger: [
      "repair plan", "repair plans", "prepare a fix", "fix plan",
      "execute repair", "approve repair", "repair status", "repair orchestration",
    ],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";
      const wantsDone = /done|completed|finished|history/.test(query);
      const statusFilter = wantsDone ? "completed,failed" : "proposed,approved,executing";
      try {
        const res = await fetch(`${API}/awareness/repair/plans?status=${statusFilter}&limit=20`, {
          signal: AbortSignal.timeout(5_000),
        });
        if (!res.ok) return { success: false, text: unavailable("Repair plans"), durationMs: Date.now() - start };
        const data = await res.json() as {
          ok: boolean;
          counts: { draft: number; proposed: number; approved: number; executing: number; completed: number; failed: number; rejected: number; cancelled: number; total: number };
          plans: Array<{
            id: string;
            title: string;
            summary: string;
            rationale: string;
            riskLevel: string;
            status: string;
            steps: Array<{ id: string; type: string; description: string; status: string; result?: { ok: boolean; note: string; verdict?: string }; error?: string }>;
            affectedFiles: string[];
            sourceLoopId?: string;
            verificationOk?: boolean;
            verificationNote?: string;
            totalCost?: number;
            createdAt: string;
            updatedAt: string;
          }>;
        };
        if (!data.ok) return { success: false, text: "Repair endpoint returned not-ok.", durationMs: Date.now() - start };

        const lines: string[] = [`[${stamp()}, Squidley repair plans]`];
        const c = data.counts;
        lines.push(`Totals: ${c.total} plans — ${c.proposed} proposed, ${c.approved} approved, ${c.executing} executing, ${c.completed} completed, ${c.failed} failed.`);

        if (data.plans.length === 0) {
          lines.push("");
          lines.push(wantsDone ? "No completed or failed plans on record." : "No active repair plans. Ask me to prepare one from a diagnosis.");
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        for (const p of data.plans.slice(0, 4)) {
          lines.push("");
          lines.push(`── [${p.riskLevel.toUpperCase()}/${p.status}] ${clip(p.title, 80)}`);
          lines.push(`id ${p.id}${p.sourceLoopId ? ` · loop ${p.sourceLoopId}` : ""}${p.totalCost ? ` · $${p.totalCost.toFixed(4)}` : ""}`);
          if (p.rationale && p.rationale !== p.summary) lines.push(`Rationale: ${clip(p.rationale, 180)}`);
          lines.push("Steps:");
          for (const s of p.steps.slice(0, 5)) {
            const mark = s.status === "completed" ? "✓" : s.status === "failed" ? "✗" : s.status === "running" ? "▶" : s.status === "skipped" ? "—" : "·";
            const detail = s.result?.note ?? s.error ?? "";
            lines.push(`  ${mark} [${s.type}] ${clip(s.description, 70)}${detail ? ` — ${clip(detail, 80)}` : ""}`);
          }
          if (p.verificationNote) {
            lines.push(`Verification: ${p.verificationOk ? "OK" : "FAIL"} — ${p.verificationNote}`);
          }
          if (p.status === "proposed") lines.push(`Awaiting approval. POST /awareness/repair/plans/${p.id}/approve`);
          if (p.status === "approved") lines.push(`Approved — execute with POST /awareness/repair/plans/${p.id}/execute`);
          if (p.status === "executing") lines.push(`In flight — poll GET /awareness/repair/plans/${p.id}`);
        }
        if (data.plans.length > 4) lines.push(`(${data.plans.length - 4} more not shown)`);

        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      } catch (err) {
        return { success: false, text: `Repair plan lookup failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
      }
    },
  },

  // ── Awareness — Open Loops (Phase 3) ──────────────────────────────────
  {
    id: "squidley.awareness.loops",
    name: "Awareness Open Loops",
    description: "Phase 3 continuity tracking — what unresolved concerns is Squidley still watching? Includes priority, status, next check time, and recently resolved loops.",
    category: "system",
    trigger: [
      "open loops", "watchlist", "follow up", "follow-ups", "still watching",
      "unresolved", "tracked issues", "what still needs attention",
      "what are you still watching", "what's still open", "loop", "loops",
      "what got resolved", "what's recovered",
    ],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";
      const wantsResolved = /resolved|recover|closed|got better|improved/.test(query);
      try {
        const [briefingRes, loopsRes] = await Promise.all([
          fetch(`${API}/awareness/loops/briefing`, { signal: AbortSignal.timeout(4_000) }),
          fetch(`${API}/awareness/loops?status=open,watching,blocked&limit=20`, { signal: AbortSignal.timeout(4_000) }),
        ]);
        if (!briefingRes.ok || !loopsRes.ok) {
          return { success: false, text: unavailable("Awareness Loops"), durationMs: Date.now() - start };
        }
        const briefingData = await briefingRes.json() as {
          ok: boolean;
          briefing: {
            total: number;
            byStatus: { open: number; watching: number; blocked: number };
            byPriority: { critical: number; high: number; medium: number; low: number };
            topOpen: Array<{ id: string; title: string; priority: string; status: string; kind: string; nextCheckAt?: string; hitCount: number }>;
            recentlyResolved: Array<{ id: string; title: string; resolvedAt: string; kind: string }>;
          };
        };
        const loopsData = await loopsRes.json() as {
          ok: boolean;
          scheduler: { running: boolean; scheduled: boolean };
          loops: Array<{ id: string; title: string; summary: string; status: string; priority: string; kind: string; nextCheckAt?: string; lastCheckedAt?: string; hitCount: number; recheckCount: number }>;
        };

        const b = briefingData.briefing;
        const lines: string[] = [`[${stamp()}, Squidley open loops]`];
        lines.push(`Scheduler: ${loopsData.scheduler.scheduled ? "running" : "offline"} · ${b.total} active (${b.byStatus.open} open, ${b.byStatus.watching} watching${b.byStatus.blocked > 0 ? `, ${b.byStatus.blocked} blocked` : ""}).`);
        if (b.byPriority.critical > 0 || b.byPriority.high > 0) {
          lines.push(`Priority mix: ${b.byPriority.critical} critical, ${b.byPriority.high} high, ${b.byPriority.medium} medium, ${b.byPriority.low} low.`);
        }

        if (wantsResolved && b.recentlyResolved.length > 0) {
          lines.push("");
          lines.push("Recently resolved (last 24h):");
          for (const r of b.recentlyResolved.slice(0, 5)) {
            lines.push(`  - ${clip(r.title, 100)} (${r.kind}, ${ago(r.resolvedAt)})`);
          }
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        if (loopsData.loops.length === 0) {
          lines.push("");
          lines.push("No open loops — the watchlist is clean.");
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        lines.push("");
        lines.push("Currently watching:");
        for (const l of loopsData.loops.slice(0, 8)) {
          const next = l.nextCheckAt ? `next ${ago(l.nextCheckAt)}` : "(no schedule)";
          const last = l.lastCheckedAt ? `last ${ago(l.lastCheckedAt)}` : "";
          const badge = `[${l.priority.toUpperCase()}/${l.status}]`;
          lines.push(`  ${badge} ${clip(l.title, 80)}${l.hitCount > 1 ? ` ×${l.hitCount}` : ""} — ${next}${last ? `, ${last}` : ""}`);
          if (l.summary && l.summary !== l.title) lines.push(`    ${clip(l.summary, 120)}`);
        }
        if (loopsData.loops.length > 8) {
          lines.push(`  ... and ${loopsData.loops.length - 8} more`);
        }

        if (b.recentlyResolved.length > 0) {
          lines.push("");
          lines.push(`Resolved recently: ${b.recentlyResolved.slice(0, 3).map(r => clip(r.title, 50)).join(" · ")}`);
        }

        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      } catch (err) {
        return { success: false, text: `Awareness loops lookup failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
      }
    },
  },

  // ── Awareness — Diagnosis (Phase 2) ──────────────────────────────────
  {
    id: "squidley.awareness.diagnose",
    name: "Awareness Diagnosis",
    description: "Phase 2 self-diagnosis: investigate current warnings with targeted tools and return status, likely cause, evidence, and proposed interventions.",
    category: "system",
    trigger: [
      "diagnose", "investigate", "what's actually wrong", "figure out what",
      "root cause", "look into", "check on", "run diagnosis", "diagnosis",
      "what should we do about", "can you investigate", "prepare a fix",
    ],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";
      const force = /fresh|re-?run|force/.test(query);
      const path = `/awareness/diagnoses${force ? "?force=1" : ""}`;
      try {
        const res = await fetch(`${API}${path}`, { signal: AbortSignal.timeout(15_000) });
        if (!res.ok) return { success: false, text: `Diagnosis endpoint returned ${res.status}.`, durationMs: Date.now() - start };
        const data = await res.json() as {
          ok: boolean;
          cached?: boolean;
          bundle?: {
            generatedAt: string;
            durationMs: number;
            reportSeverity: string;
            reportSummary: string;
            diagnoses: Array<{
              id: string;
              diagnoser: string;
              trigger: { title: string; source: string; severity: string };
              status: string;
              summary: string;
              likelyCause?: string;
              confidence: number;
              investigationSteps: string[];
              evidence: Array<{ kind: string; title: string; detail?: string }>;
              interventions: Array<{ kind: string; title: string; rationale: string; approvalPolicy: string; severity: string }>;
              affectedFiles?: string[];
            }>;
            skipped: Array<{ source: string; reason: string }>;
          };
        };
        if (!data.ok || !data.bundle) return { success: false, text: "Diagnosis bundle returned not-ok.", durationMs: Date.now() - start };

        const b = data.bundle;
        const lines: string[] = [`[${stamp()}, awareness diagnosis — ${data.cached ? "cached" : "fresh"}, ${b.durationMs}ms]`];
        lines.push(`Report severity: ${b.reportSeverity.toUpperCase()} — ${b.reportSummary}`);

        if (b.diagnoses.length === 0) {
          lines.push("");
          lines.push("Nothing actively diagnosable in the current report.");
          if (b.skipped.length > 0) {
            lines.push(`(Skipped ${b.skipped.length}: ${b.skipped.slice(0, 3).map(s => `${s.source} — ${clip(s.reason, 40)}`).join("; ")})`);
          }
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        for (const d of b.diagnoses.slice(0, 4)) {
          lines.push("");
          lines.push(`── ${d.diagnoser.toUpperCase()} · ${d.status} · confidence ${Math.round(d.confidence * 100)}%`);
          lines.push(`Trigger: ${d.trigger.title}`);
          lines.push(`Summary: ${d.summary}`);
          if (d.likelyCause) lines.push(`Likely cause: ${clip(d.likelyCause, 240)}`);
          if (d.affectedFiles && d.affectedFiles.length > 0) {
            lines.push(`Affected files: ${d.affectedFiles.slice(0, 5).join(", ")}${d.affectedFiles.length > 5 ? ` (+${d.affectedFiles.length - 5} more)` : ""}`);
          }
          if (d.investigationSteps.length > 0) {
            lines.push(`Investigated: ${d.investigationSteps.join(" → ")}`);
          }
          if (d.evidence.length > 0) {
            lines.push(`Evidence:`);
            for (const ev of d.evidence.slice(0, 3)) {
              lines.push(`  • ${clip(ev.title, 100)}${ev.detail ? ` — ${clip(ev.detail, 120)}` : ""}`);
            }
          }
          if (d.interventions.length > 0) {
            lines.push(`Recommended actions:`);
            for (const int of d.interventions.slice(0, 3)) {
              const gate = int.approvalPolicy === "advisory" ? "(advisory)" : int.approvalPolicy === "auto-safe" ? "(auto-safe)" : "(needs approval)";
              lines.push(`  • ${int.title} ${gate} — ${clip(int.rationale, 140)}`);
            }
          }
        }

        if (b.diagnoses.length > 4) {
          lines.push("");
          lines.push(`(${b.diagnoses.length - 4} more diagnoses not shown — ask for "full diagnosis" to see them)`);
        }
        if (b.skipped.length > 0) {
          lines.push("");
          lines.push(`Skipped ${b.skipped.length} item${b.skipped.length === 1 ? "" : "s"}: ${b.skipped.slice(0, 3).map(s => s.source).join(", ")}`);
        }

        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      } catch (err) {
        return { success: false, text: `Diagnosis lookup failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
      }
    },
  },

  // ── Caput — Build Orchestrator (Aedis Bridge) ────────────────────────
  {
    id: "squidley.awareness.caput",
    name: "Caput (Build Orchestrator)",
    description: "Dispatches build tasks to Aedis, reads build receipts, queries build memory, and asks Loqui questions about repos.",
    category: "system",
    trigger: [
      "caput", "ask caput", "build with aedis", "aedis build", "dispatch build",
      "what has aedis built", "aedis status", "build memory", "ask loqui",
    ],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = (input?.query ?? "").trim();

      const lines: string[] = [`[${stamp()}, Caput — Aedis bridge]`];

      const wantsBuild = /build|dispatch|change|add|fix|modify|create|refactor/.test(query);
      const wantsStatus = /status|verdict|result|commit|files touched/.test(query);
      const wantsMemory = /memory|history|past|what.*built|recent/.test(query);
      const wantsLoqui = /loqui|ask|question|about|explain|what does/.test(query);

      if (wantsBuild) {
        const prompt = query
          .replace(/^(build with aedis|aedis build|dispatch build|caput|ask caput)\b/gi, "")
          .replace(/in\s+([^,]+(?:repo|\.git)[^,]*)/gi, "")
          .trim();
        try {
          const result = await aedis_build(prompt, "/mnt/ai/squidley-v2");
          lines.push(`Dispatched to Aedis: "${clip(prompt, 100)}"`);
          lines.push(`Task ID: ${result.taskId} — status: ${result.status}`);
          lines.push("Watch the run at http://localhost:18796");
        } catch (err) {
          return { success: false, text: `Caput build dispatch failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
        }
      } else if (wantsStatus) {
        const mem = await aedis_memory("/mnt/ai/squidley-v2");
        lines.push("Aedis recent activity:");
        lines.push(`  ${mem.totalTasks} tasks total · $${mem.totalCost.toFixed(4)} total cost · $${mem.avgCost.toFixed(4)} avg`);
        if (mem.lastTask !== "none") lines.push(`  Last: "${clip(mem.lastTask, 80)}" — ${mem.lastVerdict}`);
        lines.push("Use a task ID for specific status: 'aedis status [taskId]'");
      } else if (wantsMemory) {
        const mem = await aedis_memory("/mnt/ai/squidley-v2");
        lines.push(`Aedis build memory for /mnt/ai/squidley-v2:`);
        lines.push(`  ${mem.totalTasks} tasks · $${mem.totalCost.toFixed(4)} total · $${mem.avgCost.toFixed(4)} avg`);
        lines.push(`  Recent files: ${mem.recentFiles.join(", ") || "none"}`);
        if (mem.lastTask !== "none") lines.push(`  Last: "${clip(mem.lastTask, 80)}" — ${mem.lastVerdict}`);
      } else if (wantsLoqui) {
        const question = query
          .replace(/^(ask loqui|loqui|ask aedis|aedis loqui|caput)\b/gi, "")
          .trim();
        if (!question) {
          lines.push("Usage: 'ask loqui [question about the repo]'");
        } else {
          try {
            const result = await aedis_loqui(question, "/mnt/ai/squidley-v2");
            lines.push(`Aedis Loqui:\n${result.answer}`);
          } catch (err) {
            return { success: false, text: `Caput loqui failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
          }
        }
      } else {
        lines.push("Caput — Aedis bridge for Squidley");
        lines.push("Usage:");
        lines.push("  'build with aedis [prompt]' — dispatch a build task");
        lines.push("  'aedis status' — recent activity summary");
        lines.push("  'build memory' — show Aedis memory for this repo");
        lines.push("  'ask loqui [question]' — ask Aedis about the codebase");
        lines.push("Aedis: http://localhost:18796 — 5-worker pipeline, ~$0.03/task.");
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Awareness — Autonomy (Phase 5) ────────────────────────────────────
  {
    id: "squidley.awareness.autonomy",
    name: "Autonomy Stewardship",
    description: "Phase 5 bounded autonomy — what Squidley auto-checked, why it was allowed, what it refused to do automatically, and what's scheduled next.",
    category: "system",
    trigger: [
      "autonomy", "auto action", "auto actions", "self scheduled", "self check",
      "what did you check", "what have you done automatically", "what did you auto run",
      "scheduled work", "scheduled maintenance", "steward", "stewardship",
      "autonomous", "kill switch", "auto mode", "autonomy mode", "autonomy policy",
      "what are you doing on your own", "what refused", "what was denied",
    ],
    requiresApproval: false,
    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";
      const wantsPolicy = /policy|mode|budget|kill|off|disable|enable/.test(query);
      const wantsRefused = /refused|denied|approval|skip|blocked/.test(query);
      try {
        const res = await fetch(`${API}/awareness/autonomy/status`, {
          signal: AbortSignal.timeout(4_000),
        });
        if (!res.ok) return { success: false, text: unavailable("Autonomy"), durationMs: Date.now() - start };
        const data = await res.json() as {
          ok: boolean;
          scheduler: { running: boolean; scheduled: boolean; mode: string };
          policy: {
            mode: string;
            silenceThreshold: string;
            budget: {
              maxActionsPerHour: number;
              maxActionsPerDay: number;
              maxCostPerDay: number;
              minGapBetweenActionsSec: number;
              blockingSeverityFloor: string;
            };
          };
          briefing: {
            mode: string;
            enabled: boolean;
            jobCount: number;
            jobsEnabled: number;
            nextRunAt: string | null;
            nextJobKind: string | null;
            last24h: { executed: number; skipped: number; failed: number; denied: number; observed: number; costUsd: number };
            budget: { hourlyRemaining: number; dailyRemaining: number; dailyCostRemainingUsd: number };
            recentReceipts: Array<{ id: string; at: string; kind: string; status: string; summary: string }>;
            pendingApproval: Array<{ kind: string; title: string; reason: string }>;
          };
        };
        if (!data.ok) return { success: false, text: "Autonomy endpoint returned not-ok.", durationMs: Date.now() - start };

        const lines: string[] = [`[${stamp()}, Squidley autonomy]`];
        const b = data.briefing;
        const modeLabel = {
          off: "OFF (kill switch)",
          observe: "OBSERVE-ONLY",
          safe: "SAFE-AUTONOMY",
          manual: "MANUAL-ONLY",
        }[b.mode] ?? b.mode.toUpperCase();
        lines.push(`Mode: ${modeLabel} · scheduler ${data.scheduler.scheduled ? "scheduled" : "offline"}.`);
        lines.push(`Jobs: ${b.jobsEnabled}/${b.jobCount} enabled${b.nextJobKind && b.nextRunAt ? ` · next: ${b.nextJobKind} ${ago(b.nextRunAt)}` : ""}.`);

        if (wantsPolicy) {
          const p = data.policy;
          lines.push("");
          lines.push("Budget:");
          lines.push(`  Actions/hour: ${b.budget.hourlyRemaining}/${p.budget.maxActionsPerHour} remaining`);
          lines.push(`  Actions/day : ${b.budget.dailyRemaining}/${p.budget.maxActionsPerDay} remaining`);
          lines.push(`  Cost/day    : $${b.budget.dailyCostRemainingUsd.toFixed(4)}/$${p.budget.maxCostPerDay.toFixed(4)} remaining`);
          lines.push(`  Min gap     : ${p.budget.minGapBetweenActionsSec}s between actions`);
          lines.push(`  Blocking    : pause on ${p.budget.blockingSeverityFloor}+ awareness severity`);
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        lines.push("");
        lines.push(`Last 24h — ${b.last24h.executed} ran, ${b.last24h.denied} denied, ${b.last24h.failed} failed, ${b.last24h.observed} observed · $${b.last24h.costUsd.toFixed(4)}.`);

        if (wantsRefused) {
          if (b.pendingApproval.length === 0) {
            lines.push("");
            lines.push("Nothing is queued as approval-needed right now.");
          } else {
            lines.push("");
            lines.push("Refused to auto-run (approval-gated):");
            for (const p of b.pendingApproval.slice(0, 6)) {
              lines.push(`  - [${p.kind}] ${clip(p.title, 80)} — ${clip(p.reason, 80)}`);
            }
          }
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        if (b.recentReceipts.length > 0) {
          lines.push("");
          lines.push("Recent auto-actions:");
          for (const r of b.recentReceipts.slice(0, 6)) {
            const mark = r.status === "executed" ? "✓" : r.status === "observed" ? "◌" : r.status === "denied" ? "✗" : r.status === "failed" ? "!" : "·";
            lines.push(`  ${mark} [${r.kind}] ${clip(r.summary, 100)} — ${ago(r.at)}`);
          }
        } else {
          lines.push("");
          lines.push("No recent auto-actions. The scheduler is quiet.");
        }

        if (b.pendingApproval.length > 0) {
          lines.push("");
          lines.push(`Approval-gated (not auto-run): ${b.pendingApproval.slice(0, 3).map(p => p.kind).join(", ")}.`);
        }

        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      } catch (err) {
        return { success: false, text: `Autonomy lookup failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
      }
    },
  },

