          } else {
            lines.push("");
            lines.push("Recently applied:");
            for (const r of b.recentlyApplied.slice(0, 5)) {
              const imp = typeof r.improvement === "number"
                ? r.improvement > 0.05 ? ` · ↑ ${(r.improvement * 100).toFixed(1)}% improvement`
                : r.improvement < -0.05 ? ` · ↓ ${(r.improvement * 100).toFixed(1)}%`
                : " · (no measurable change)"
                : " · (outcome pending)";
              lines.push(`  ✓ [${r.category}] ${clip(r.title, 80)} — ${ago(r.appliedAt)}${imp}`);
            }
          }
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        if (wantsApproval) {
          if (b.pendingApproval.length === 0) {
            lines.push("");
            lines.push("No recommendations are pending approval.");
          } else {
            lines.push("");
            lines.push("Pending approval:");
            for (const p of b.pendingApproval.slice(0, 6)) {
              lines.push(`  [${p.impact.toUpperCase()}] ${clip(p.title, 80)} — ${clip(p.reason, 80)}`);
            }
          }
          return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
        }

        if (b.inefficiencies.length > 0) {
          lines.push("");
          lines.push("Current inefficiencies:");
          for (const i of b.inefficiencies.slice(0, 4)) {
            lines.push(`  - ${clip(i, 120)}`);
          }
        }

        if (b.topProposed.length > 0) {
          lines.push("");
          lines.push("Top recommendations:");
          for (const r of b.topProposed.slice(0, 5)) {
            const gate = r.requiresApproval ? "approval" : "auto-eligible";
            lines.push(`  [${r.impact.toUpperCase()}/${r.kind}] ${clip(r.title, 80)} · ${gate} · ${(r.confidence * 100).toFixed(0)}%`);
          }
        } else {
          lines.push("");
          lines.push("Nothing to optimize right now. The ecosystem is tidy.");
        }

        if (b.recentlyApplied.length > 0) {
          lines.push("");
          lines.push(`Last applied: ${clip(b.recentlyApplied[0]!.title, 100)} (${ago(b.recentlyApplied[0]!.appliedAt)}).`);
        }

        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      } catch (err) {
        return { success: false, text: `Optimization lookup failed: ${String(err).slice(0, 200)}`, durationMs: Date.now() - start };
      }
    },
  },

];

export function registerSystemAwarenessTools(toolRunner: { register: (tool: unknown) => void }): number {
