        }
      }

      if (local.length > 0) {
        lines.push(`Best local: ${local[0]!.model_name} (${local[0]!.overall_score}).`);
      }

      if (plb?.ok && personalityModels.length > 0) {
        const p = personalityModels[0]!;
        lines.push(`Personality leader: ${p.model_name} averaging ${p.average_score}.`);
      }

      const latest = latestIso(lb.models.map((model) => model.last_run));
      if (latest && stale(latest)) {
        lines.push(`Last benchmark was ${ago(latest)} — might be worth a fresh run.`);
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

  // ── Magister ──────────────────────────────────────────────────────────────
  {
    id: "squidley.awareness.magister",
    name: "Magister Learning",
    description: "Learning campaigns, companion sessions, mastery progress",
    category: "system",
    trigger: ["magister", "learning", "vietnamese", "mandarin", "linh", "wei", "campaign", "lesson", "study", "progress", "mastery", "companion"],
    requiresApproval: false,
