      const data = await get<{ ok: boolean; ideas: Array<{ id: string; content: string; status: string; created_at: string; promoted_to: string | null }> }>("/animus/ideas");

      if (!data?.ok || !data.ideas) return { success: false, text: unavailable("Animus"), durationMs: Date.now() - start };

      const ideas = data.ideas;
      const total = ideas.length;
      const staleIdeas = ideas.filter(i => i.status === "stale");
      const agingIdeas = ideas.filter(i => i.status === "aging");
      const freshIdeas = ideas.filter(i => i.status === "fresh");
      const parkedIdeas = ideas.filter(i => i.status === "parked");
      const promoted = ideas.filter(i => i.promoted_to);

      const lines: string[] = [`[${stamp()}, live data]`];

      if (total === 0) {
        lines.push("The vault is empty — no ideas captured yet.");
        return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
      }

      lines.push(`You've got ${total} idea${total > 1 ? "s" : ""} in the vault: ${freshIdeas.length} fresh, ${agingIdeas.length} aging, ${staleIdeas.length} stale, ${parkedIdeas.length} parked.`);

      if (staleIdeas.length > 0) {
        lines.push("");
        lines.push(`${staleIdeas.length} idea${staleIdeas.length > 1 ? "s have" : " has"} been sitting for 3+ weeks — worth a look:`);
        for (const idea of staleIdeas.slice(0, 5)) {
          lines.push(`  - "${clip(idea.content, 100)}" (${ago(idea.created_at)})`);
        }
        if (staleIdeas.length > 5) lines.push(`  ... and ${staleIdeas.length - 5} more.`);
      }

      if (agingIdeas.length > 0) {
        lines.push("");
        lines.push(`${agingIdeas.length} aging (1-3 weeks):`);
        for (const idea of agingIdeas.slice(0, 3)) {
          lines.push(`  - "${clip(idea.content, 100)}" (${ago(idea.created_at)})`);
        }
      }

      if (freshIdeas.length > 0 && freshIdeas.length <= 5) {
        lines.push("");
        lines.push(`${freshIdeas.length} fresh:`);
        for (const idea of freshIdeas.slice(0, 3)) {
          lines.push(`  - "${clip(idea.content, 100)}" (${ago(idea.created_at)})`);
        }
      }

      if (promoted.length > 0) {
        lines.push("");
        lines.push(`${promoted.length} idea${promoted.length > 1 ? "s" : ""} already promoted.`);
