/**
 * weather-formatter.ts
 * Formats a Weather Guard API response into a human-readable plain text string.
 */

export interface WeatherAlert {
  event: string;
  severity: string;
  headline?: string;
  description?: string;
  expires?: string;
}

export interface WeatherWind {
  speed: number;
  gust?: number;
  direction: string;
  unit?: string;
}

export interface WeatherGuardResponse {
  temperature: {
    value: number;
    unit?: string; // 'F' | 'C' — defaults to 'F'
    feelsLike?: number;
  };
  conditions: {
    summary: string;
    humidity?: number;
    visibility?: number;
    visibilityUnit?: string;
  };
  wind: WeatherWind;
  alerts?: WeatherAlert[];
  location?: string;
  observedAt?: string;
}

/**
 * Formats a Weather Guard API response object into a plain text weather report.
 *
 * @param response - The Weather Guard API response object
 * @returns A formatted, human-readable plain text string
 */
export function formatWeatherReport(response: WeatherGuardResponse): string {
  const lines: string[] = [];
  const tempUnit = response.temperature.unit ?? 'F';
  const windUnit = response.wind.unit ?? 'mph';

  // Header
  if (response.location) {
    lines.push(`Weather Report — ${response.location}`);
  } else {
    lines.push('Weather Report');
  }

  if (response.observedAt) {
    const observed = new Date(response.observedAt);
    lines.push(`Observed: ${observed.toLocaleString()}`);
  }

  lines.push('');

  // Temperature
  lines.push('TEMPERATURE');
  lines.push(`  Current : ${response.temperature.value}°${tempUnit}`);
  if (response.temperature.feelsLike !== undefined) {
    lines.push(`  Feels like: ${response.temperature.feelsLike}°${tempUnit}`);
  }

  lines.push('');

  // Conditions
  lines.push('CONDITIONS');
  lines.push(`  Summary : ${response.conditions.summary}`);
  if (response.conditions.humidity !== undefined) {
    lines.push(`  Humidity: ${response.conditions.humidity}%`);
  }
  if (response.conditions.visibility !== undefined) {
    const visUnit = response.conditions.visibilityUnit ?? 'mi';
    lines.push(`  Visibility: ${response.conditions.visibility} ${visUnit}`);
  }

  lines.push('');

  // Wind
  lines.push('WIND');
  lines.push(`  Speed    : ${response.wind.speed} ${windUnit} ${response.wind.direction}`);
  if (response.wind.gust !== undefined) {
    lines.push(`  Gusts    : up to ${response.wind.gust} ${windUnit}`);
  }

  // Active Alerts
  if (response.alerts && response.alerts.length > 0) {
    lines.push('');
    lines.push('ACTIVE ALERTS');
    for (const alert of response.alerts) {
      lines.push(`  ⚠ [${alert.severity.toUpperCase()}] ${alert.event}`);
      if (alert.headline) {
        lines.push(`    ${alert.headline}`);
      }
      if (alert.description) {
        // Indent multi-line descriptions
        const descLines = alert.description.split('\n');
        for (const dl of descLines) {
          lines.push(`    ${dl}`);
        }
      }
      if (alert.expires) {
        const exp = new Date(alert.expires);
        lines.push(`    Expires: ${exp.toLocaleString()}`);
      }
    }
  } else {
    lines.push('');
    lines.push('ACTIVE ALERTS');
    lines.push('  None');
  }

  return lines.join('\n');
}


