  contextLength = 4096,
): number {
  const bits = QUANT_BITS[quant.toUpperCase()] ?? 4;
  const modelBytes = paramBillions * 1e9 * (bits / 8);
  const modelGB = modelBytes / 1024 ** 3;
  const kvCacheGB = (contextLength * paramBillions * 0.002) / 1024;
  const overhead = 0.5;
  return Math.round((modelGB + kvCacheGB + overhead) * 10) / 10;
}

export function vramFitsGPU(
  estimateGB: number,
  gpuVramGB: number,
): "fits" | "tight" | "exceeds" {
  if (estimateGB <= gpuVramGB * 0.85) return "fits";
  if (estimateGB <= gpuVramGB) return "tight";
  return "exceeds";
}

/** Parse param size from string like "7B", "3.5B", "70B" */
export function parseParamBillions(s: string | null): number {
  if (!s) return 7;
  const match = s.match(/([\d.]+)\s*[bB]/);
  return match ? parseFloat(match[1]!) : 7;
}

// ── Hardware Gate ──────────────────────────────────────────────────────────

export interface ModelHardwareConfig {
  vram_required_gb: number;
  allows_cpu_offload: boolean;
  min_vram_gb?: number | null;
  min_ram_gb?: number | null;
}

export interface HardwareStatus {
  gpu_vram_gb: number;
  gpu_free_gb: number;
  system_ram_gb: number;
  ram_free_gb: number;
}

export type GateResult =
  | { allowed: true; mode: "gpu" | "cpu+gpu"; offload_gb: number }
  | { allowed: false; reason: string; shortfall_gb: number };

/**
 * Hardware gate: checks if a model can run on available hardware.
 *
 * - If allows_cpu_offload is false: vram_required_gb is a hard GPU-only limit
 * - If allows_cpu_offload is true: checks min_vram_gb (GPU) + min_ram_gb (RAM)
 *   The model runs hybrid — layers split between GPU and CPU/RAM.
 */
export function hardwareGate(
  config: ModelHardwareConfig,
  hw: HardwareStatus,
): GateResult {
  if (!config.allows_cpu_offload) {
    if (config.vram_required_gb <= hw.gpu_free_gb) {
      return { allowed: true, mode: "gpu", offload_gb: 0 };
    }
    return {
      allowed: false,
      reason: `Needs ${config.vram_required_gb}GB VRAM, ${hw.gpu_free_gb}GB free`,
      shortfall_gb: config.vram_required_gb - hw.gpu_free_gb,
    };
  }

  const minVram = config.min_vram_gb ?? config.vram_required_gb;
  const minRam = config.min_ram_gb ?? 0;

  if (minVram > hw.gpu_free_gb) {
    return {
      allowed: false,
      reason: `Needs ${minVram}GB VRAM minimum, ${hw.gpu_free_gb}GB free`,
      shortfall_gb: minVram - hw.gpu_free_gb,
    };
  }

  if (minRam > hw.ram_free_gb) {
    return {
      allowed: false,
      reason: `Needs ${minRam}GB RAM for offload, ${hw.ram_free_gb}GB free`,
      shortfall_gb: minRam - hw.ram_free_gb,
    };
  }

  const totalNeeded = config.vram_required_gb;
  const gpuUsed = Math.min(totalNeeded, hw.gpu_free_gb);
  const offloadToRam = totalNeeded - gpuUsed;

  if (offloadToRam <= 0) {
    return { allowed: true, mode: "gpu", offload_gb: 0 };
  }

  return {
    allowed: true,
    mode: "cpu+gpu",
    offload_gb: Math.round(offloadToRam * 10) / 10,
  };
}


