import { mkdir, readFile, writeFile } from "node:fs/promises";
import { basename, join } from "node:path";

/** Voice role IDs — "system" and "narrator" are built-in, companions are dynamic */
export type VoiceRoleId = string;
export type VoiceProviderId = "elevenlabs" | "piper";

export interface VoiceRoleAssignment {
  role: VoiceRoleId;
  provider: VoiceProviderId;
  voiceId: string | null;
  modelId: string | null;
  label: string | null;
  fallbackProvider: "piper";
  fallbackVoice: string | null;
  updatedAt: string;
}

export interface VoiceRoleState {
  system: VoiceRoleAssignment;
  narrator: VoiceRoleAssignment;
  [key: string]: VoiceRoleAssignment;
}

function baseDir(): string {
  return process.env["SQUIDLEY_BASE_DIR"] ?? process.cwd();
}

function statePath(): string {
  return join(baseDir(), "state", "nous-voice-roles.json");
}

function defaultFallbackVoice(): string | null {
  const value = process.env["PIPER_VOICE"]?.trim();
  if (!value) return null;
  const file = basename(value);
  return file.replace(/\.onnx$/i, "") || value;
}

function defaultAssignment(role: VoiceRoleId): VoiceRoleAssignment {
  const envVoice = role === "system"
    ? process.env["ELEVENLABS_SYSTEM_VOICE_ID"]?.trim()
    : process.env["ELEVENLABS_NARRATOR_VOICE_ID"]?.trim();
  const envLabel = role === "system"
    ? process.env["ELEVENLABS_SYSTEM_VOICE_LABEL"]?.trim()
    : process.env["ELEVENLABS_NARRATOR_VOICE_LABEL"]?.trim();
  const envModel = role === "system"
    ? process.env["ELEVENLABS_SYSTEM_MODEL_ID"]?.trim()
    : process.env["ELEVENLABS_NARRATOR_MODEL_ID"]?.trim();

  return {
    role,
    provider: "elevenlabs",
    voiceId: envVoice || null,
    modelId: envModel || null,
    label: envLabel || null,
    fallbackProvider: "piper",
    fallbackVoice: defaultFallbackVoice(),
    updatedAt: new Date(0).toISOString(),
  };
}

function normalizeRole(role: VoiceRoleId, value: Partial<VoiceRoleAssignment> | null | undefined): VoiceRoleAssignment {
  const base = defaultAssignment(role);
  return {
    role,
    provider: value?.provider === "piper" ? "piper" : "elevenlabs",
    voiceId: typeof value?.voiceId === "string" && value.voiceId.trim() ? value.voiceId.trim() : null,
    modelId: typeof value?.modelId === "string" && value.modelId.trim() ? value.modelId.trim() : null,
    label: typeof value?.label === "string" && value.label.trim() ? value.label.trim() : null,
    fallbackProvider: "piper",
    fallbackVoice: typeof value?.fallbackVoice === "string" && value.fallbackVoice.trim() ? value.fallbackVoice.trim() : base.fallbackVoice,
    updatedAt: typeof value?.updatedAt === "string" && value.updatedAt ? value.updatedAt : base.updatedAt,
  };
}

function normalizeState(raw: Record<string, unknown> | null | undefined): VoiceRoleState {
  const state: VoiceRoleState = {
    system: normalizeRole("system", raw?.system as Partial<VoiceRoleAssignment> | undefined),
    narrator: normalizeRole("narrator", raw?.narrator as Partial<VoiceRoleAssignment> | undefined),
  };
  // Preserve any dynamic companion roles
  if (raw) {
    for (const [key, value] of Object.entries(raw)) {
      if (key !== "system" && key !== "narrator" && value && typeof value === "object") {
        state[key] = normalizeRole(key, value as Partial<VoiceRoleAssignment>);
      }
    }
  }
  return state;
}

export async function getVoiceRoleState(): Promise<VoiceRoleState> {
  try {
    const raw = await readFile(statePath(), "utf-8");
    return normalizeState(JSON.parse(raw) as Record<string, unknown>);
  } catch {
    return normalizeState(null);
  }
}

export async function updateVoiceRole(role: VoiceRoleId, patch: Partial<VoiceRoleAssignment>): Promise<VoiceRoleState> {
  const current = await getVoiceRoleState();
  const next: VoiceRoleState = {
    ...current,
    [role]: normalizeRole(role, {
      ...current[role],
      ...patch,
      updatedAt: new Date().toISOString(),
    }),
  };
  await mkdir(join(baseDir(), "state"), { recursive: true });
  await writeFile(statePath(), JSON.stringify(next, null, 2) + "\n", "utf-8");
  return next;
}


