/**
 * Post-Action Verification
 * =========================
 * Verifies that file operations actually succeeded.
 * Not just "tool executed" — "task succeeded."
 *
 * Checks:
 *  - File exists after write
 *  - Intended content is present after edit
 *  - JSON/YAML still parses if applicable
 *  - App still builds if relevant (optional, async)
 */

import { readFile, access, stat } from "node:fs/promises";

export interface VerifyResult {
  verified: boolean;
  checks: VerifyCheck[];
  summary: string;
}

export interface VerifyCheck {
  check: string;
  passed: boolean;
  detail: string;
}

/**
 * Verify a file write operation succeeded.
 */
export async function verifyWrite(
  filePath: string,
  expectedContent: string,
): Promise<VerifyResult> {
  const checks: VerifyCheck[] = [];

  // Check 1: File exists
  try {
    await access(filePath);
    checks.push({ check: "file_exists", passed: true, detail: "File exists at target path" });
  } catch {
    checks.push({ check: "file_exists", passed: false, detail: "File does not exist after write" });
    return { verified: false, checks, summary: "Write failed — file not found" };
  }

  // Check 2: File is readable and content matches
  try {
    const actual = await readFile(filePath, "utf-8");
    if (actual === expectedContent) {
      checks.push({ check: "content_match", passed: true, detail: "Written content matches expected" });
    } else {
      checks.push({ check: "content_match", passed: false, detail: `Content mismatch: expected ${expectedContent.length} bytes, got ${actual.length} bytes` });
    }
  } catch (err) {
    checks.push({ check: "content_match", passed: false, detail: `Cannot read file: ${String(err)}` });
  }

  // Check 3: File size is reasonable
  try {
    const s = await stat(filePath);
    if (s.size === 0 && expectedContent.length > 0) {
      checks.push({ check: "size_check", passed: false, detail: "File is empty but content was expected" });
    } else {
      checks.push({ check: "size_check", passed: true, detail: `${s.size} bytes on disk` });
    }
  } catch {
    checks.push({ check: "size_check", passed: false, detail: "Cannot stat file" });
  }

  // Check 4: JSON/YAML parse check if applicable
  if (filePath.endsWith(".json")) {
    try {
      const content = await readFile(filePath, "utf-8");
      JSON.parse(content);
      checks.push({ check: "json_valid", passed: true, detail: "Valid JSON" });
    } catch (err) {
      checks.push({ check: "json_valid", passed: false, detail: `Invalid JSON: ${String(err)}` });
    }
  }

  const allPassed = checks.every(c => c.passed);
  return {
    verified: allPassed,
    checks,
    summary: allPassed ? "All verification checks passed" : `${checks.filter(c => !c.passed).length} check(s) failed`,
  };
}

/**
 * Verify a file edit operation succeeded.
 */
export async function verifyEdit(
  filePath: string,
  searchString: string,
  replaceString: string,
  replaceAll: boolean,
): Promise<VerifyResult> {
  const checks: VerifyCheck[] = [];

  // Check 1: File exists
  try {
    await access(filePath);
    checks.push({ check: "file_exists", passed: true, detail: "File exists" });
  } catch {
    checks.push({ check: "file_exists", passed: false, detail: "File not found" });
    return { verified: false, checks, summary: "Edit target not found" };
  }

  // Check 2: Search string is no longer present (for replace-all) or replacement is present
  try {
    const content = await readFile(filePath, "utf-8");

    if (replaceAll) {
      const stillPresent = content.includes(searchString);
      checks.push({
        check: "search_removed",
        passed: !stillPresent,
        detail: stillPresent ? "Original search string still found in file" : "Search string fully replaced",
      });
    }

    const replacementPresent = content.includes(replaceString);
    checks.push({
      check: "replacement_present",
      passed: replacementPresent,
      detail: replacementPresent ? "Replacement text found in file" : "Replacement text not found — edit may have failed",
    });
  } catch (err) {
    checks.push({ check: "content_check", passed: false, detail: `Cannot read file: ${String(err)}` });
  }

  // Check 3: JSON validity if applicable
  if (filePath.endsWith(".json")) {
    try {
      const content = await readFile(filePath, "utf-8");
      JSON.parse(content);
      checks.push({ check: "json_valid", passed: true, detail: "Valid JSON after edit" });
    } catch (err) {
      checks.push({ check: "json_valid", passed: false, detail: `JSON broken after edit: ${String(err)}` });
    }
  }

  // Check 4: TypeScript syntax check (lightweight — just check for obvious breaks)
  if (filePath.endsWith(".ts") || filePath.endsWith(".tsx")) {
    try {
      const content = await readFile(filePath, "utf-8");
      // Check for unmatched braces/brackets as a basic sanity check
      const opens = (content.match(/[{(\[]/g) ?? []).length;
      const closes = (content.match(/[})\]]/g) ?? []).length;
      const balanced = Math.abs(opens - closes) < 3; // small tolerance for template literals
      checks.push({
        check: "syntax_sanity",
        passed: balanced,
        detail: balanced ? "Brace/bracket balance looks correct" : `Possible syntax break: ${opens} opens vs ${closes} closes`,
      });
    } catch { /* skip */ }
  }

  const allPassed = checks.every(c => c.passed);
  return {
    verified: allPassed,
    checks,
    summary: allPassed ? "All verification checks passed" : `${checks.filter(c => !c.passed).length} check(s) failed`,
  };
}
