const API = `http://127.0.0.1:${process.env["SQUIDLEY_API_PORT"] ?? "18791"}`;

async function get<T>(path: string, timeoutMs = 3000): Promise<T | null> {
  const url = `${API}${path}`;
  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(timeoutMs) });
    if (!res.ok) return null;
    try {
      return await res.json() as T;
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      console.warn(`[awareness] fetch failed: json parse failed for ${url}: ${reason}`);
      return null;
    }
  } catch (error) {
    if (error instanceof DOMException && error.name === "TimeoutError") {
      console.warn(`[awareness] fetch failed: timeout for ${url} after ${timeoutMs}ms`);
      return null;
    }
    const reason = error instanceof Error ? error.message : String(error);
    console.warn(`[awareness] fetch failed: fetch failed for ${url}: ${reason}`);
    return null;
  }
}

function clip(s: string, max = 80): string {
  return s.length <= max ? s : s.slice(0, max - 1) + "…";
}

function stamp(): string {
  return new Intl.DateTimeFormat("en-US", { dateStyle: "medium", timeStyle: "short", timeZone: process.env["TZ"] || "America/Chicago" }).format(new Date());
}

function ago(iso: string): string {
  const ms = Date.now() - new Date(iso).getTime();
  const m = Math.floor(ms / 60000);
  if (m < 1) return "just now";
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  return d === 1 ? "yesterday" : `${d}d ago`;
}

function stale(iso: string | null): boolean {
  if (!iso) return true;
  const ts = new Date(iso).getTime();
  if (Number.isNaN(ts)) return true;
  return Date.now() - ts > 3600_000; // >1h = stale
}

function compareNumbersDesc(a: number, b: number): number {
  return b - a;
}

function latestIso(values: Array<string | null | undefined>): string | null {
  let latest: string | null = null;
  let latestTs = Number.NEGATIVE_INFINITY;
  for (const value of values) {
    if (!value) continue;
    const ts = Date.parse(value);
    if (Number.isNaN(ts)) continue;
    if (ts > latestTs) {
      latestTs = ts;
      latest = value;
    }
  }
  return latest;
}

function unavailable(module: string): string {
  return `I can't reach ${module} right now — the service may need a restart. Check system health if this persists.`;
}

