  // ── Provider Diagnostics ──────────────────────────────────────────────────
  {
    id: "squidley.awareness.providers",
    name: "Provider Diagnostics",
    description: "Real-time provider health: which providers can actually make calls vs. which just have billing issues",
    category: "system",
    trigger: ["provider", "providers", "openai", "anthropic", "openrouter", "minimax", "ollama", "model provider", "provider health", "provider status", "api key", "provider error", "provider fail", "which providers", "what's working", "what providers", "error rate", "failure rate", "bricked", "100% failure"],
    requiresApproval: false,
    async execute() {
      const start = Date.now();
      const [health, balances, changes, performance] = await Promise.all([
        get<{ modules: Record<string, { status: string; message?: string; expectedDegraded?: boolean }> }>("/health"),
        get<{ providers: Record<string, { providerId: string; label: string; source: string; status: string; balanceUsd: number | null; stale: boolean; message?: string }> }>("/augury/provider-balances"),
        get<{ failuresByComponent: Array<{ component: string; count: number; repeatOffender: boolean }>; counts: { modelCalls: number; failures: number } }>("/platform/changes?hours=6"),
        get<{ ok: boolean; performance: Array<{ provider: string; taskType: string; totalCalls: number; positiveSignals: number; negativeSignals: number; score: number }> }>("/brain-map/performance"),
      ]);

      const lines: string[] = [`[${stamp()}, live provider diagnostics]`];

      // 1. Module-level health (are the provider modules themselves loaded and reachable?)
      const providerModules = Object.entries(health?.modules ?? {}).filter(([k]) => k.includes("provider-"));
      if (providerModules.length > 0) {
        const healthy = providerModules.filter(([, v]) => v.status === "healthy");
        const broken = providerModules.filter(([, v]) => v.status !== "healthy" && !v.expectedDegraded);
        const optional = providerModules.filter(([, v]) => v.status !== "healthy" && v.expectedDegraded);

        if (broken.length === 0) {
          lines.push(`All ${healthy.length} provider modules healthy and accepting calls.`);
        } else {
          lines.push(`${healthy.length}/${providerModules.length} provider modules healthy.`);
          for (const [name, v] of broken) {
            lines.push(`  ✗ ${name.split(".").pop()}: ${v.status}${v.message ? ` — ${clip(v.message, 60)}` : ""}`);
          }
        }
        if (optional.length > 0) {
          lines.push(`  (${optional.map(([n]) => n.split(".").pop()).join(", ")} offline — on-demand only, this is normal)`);
        }
      }

      // 2. Actual call success/failure rates (the ground truth)
      if (changes?.counts) {
        const { modelCalls, failures } = changes.counts;
        lines.push("");
        if (failures === 0 && modelCalls > 0) {
          lines.push(`Last 6h: ${modelCalls} model calls, zero failures. All providers performing normally.`);
        } else if (failures === 0 && modelCalls === 0) {
          lines.push(`Last 6h: No model calls recorded — system may be idle.`);
        } else {
          const rate = modelCalls > 0 ? ((failures / modelCalls) * 100).toFixed(1) : "N/A";
          lines.push(`Last 6h: ${modelCalls} model calls, ${failures} failures (${rate}% failure rate).`);
        }
        const failedProviders = changes.failuresByComponent ?? [];
        if (failedProviders.length > 0) {
          lines.push("Failure breakdown:");
          for (const fp of failedProviders.slice(0, 5)) {
            lines.push(`  ${fp.component}: ${fp.count} failures${fp.repeatOffender ? " (repeat offender)" : ""}`);
          }
        }
      }

      // 3. Balance/billing status (separate from call health!)
      if (balances?.providers) {
        const cards = Object.values(balances.providers);
        const problems = cards.filter(c => c.status === "error" || c.status === "critical" || c.status === "misconfigured");
        const manualNeeded = cards.filter(c => c.source === "manual" || c.source === "unsupported");

        if (problems.length > 0 || manualNeeded.length > 0) {
          lines.push("");
          lines.push("Billing / balance status (NOTE: billing errors ≠ provider failures):");
          for (const c of cards) {
            if (c.status === "ok" && !c.stale) {
              lines.push(`  ${c.label}: $${c.balanceUsd?.toFixed(2) ?? "?"} remaining — OK`);
            } else if (c.status === "error") {
              lines.push(`  ${c.label}: billing check error — ${clip(c.message ?? "unknown", 70)}. Provider may still work fine for calls.`);
            } else if (c.source === "manual") {
              lines.push(`  ${c.label}: manual balance ($${c.balanceUsd?.toFixed(2) ?? "?"})${c.stale ? " — stale, needs update" : ""}`);
            } else if (c.source === "unsupported") {
              lines.push(`  ${c.label}: no billing API available — track balance manually`);
            } else if (c.status === "critical") {
              lines.push(`  ${c.label}: CRITICAL — $${c.balanceUsd?.toFixed(2) ?? "0"} remaining, below threshold`);
            } else {
              lines.push(`  ${c.label}: ${c.status}${c.balanceUsd != null ? ` ($${c.balanceUsd.toFixed(2)})` : ""}`);
            }
          }
        } else {
          lines.push("");
          lines.push("All provider balances look fine.");
        }
      }

      // 4. Brain Map quality signals (if available)
      if (performance?.performance && performance.performance.length > 0) {
        const byProvider = new Map<string, { calls: number; pos: number; neg: number }>();
        for (const p of performance.performance) {
          const key = p.provider;
          const existing = byProvider.get(key) ?? { calls: 0, pos: 0, neg: 0 };
          existing.calls += p.totalCalls;
          existing.pos += p.positiveSignals;
          existing.neg += p.negativeSignals;
          byProvider.set(key, existing);
        }
        const notable = [...byProvider.entries()].filter(([, v]) => v.neg > 2 || (v.calls > 5 && v.neg > v.pos));
        if (notable.length > 0) {
          lines.push("");
          lines.push("Quality signals (Brain Map):");
          for (const [name, v] of notable) {
            lines.push(`  ${name}: ${v.calls} calls, ${v.pos} positive / ${v.neg} negative signals — worth watching`);
          }
        }
      }

      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

