      const q = input.query
        .replace(/^(search for|find|look up|search squidley|search everything|anything about|what do we have on|show me everything)\s*/i, "")
        .trim();
      if (!q) return { success: false, text: "No search query found.", durationMs: Date.now() - start };

      const data = await get<{
        ok: boolean;
        total: number;
