    async execute(input?: { query?: string }) {
      const start = Date.now();
      const query = input?.query?.toLowerCase() ?? "";

      // If user wants to share/broadcast something
      const wantsBroadcast = /tell pop tart|share with|broadcast|let .* know/.test(query);
      if (wantsBroadcast) {
        const content = query.replace(/tell pop tart|share with pop tart|broadcast|let .* know/gi, "").trim();
        if (content.length > 5) {
          try {
            await fetch(`${API}/mesh/context/broadcast`, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ type: "conversation_summary", content, source: "mushin" }),
              signal: AbortSignal.timeout(10_000),
            });
            return { success: true, text: `Shared with mesh: "${content}"`, durationMs: Date.now() - start };
          } catch {
            return { success: false, text: "Failed to broadcast to mesh.", durationMs: Date.now() - start };
          }
        }
      }

      // Otherwise, show current shared context
      const data = await get<{ ok: boolean; entries: Array<{ key: string; value: unknown; source: string; updated_at: string; tags: string[] }>; total: number }>("/mesh/context");
      if (!data?.ok || data.total === 0) {
        return { success: true, text: `[${stamp()}] No shared context entries. The mesh nodes aren't sharing working state yet.\nUse "tell Pop Tart [message]" or "share with Pop Tart [info]" to broadcast context.`, durationMs: Date.now() - start };
      }

      const lines = [`[${stamp()}, ${data.total} shared context entries]`];
      for (const e of data.entries.slice(0, 10)) {
        const val = typeof e.value === "object" && e.value !== null ? (e.value as Record<string, unknown>).content ?? JSON.stringify(e.value).slice(0, 100) : String(e.value).slice(0, 100);
        lines.push(`  [${e.source}] ${e.tags.join(", ")} — ${val} (${ago(e.updated_at)})`);
      }
      return { success: true, text: lines.join("\n"), durationMs: Date.now() - start };
    },
  },

